import{t as e}from"./rolldown-runtime-H_PjY6_i.js";var i=e({R0100:()=>t,default:()=>n}),t={title:"挂机",definition:"这通常指的是玩家在游戏进行时，自己并没有操作角色，而是让角色静止不动或者使用自动战斗功能。",description:"挂机行为可能是因为玩家离开了电脑或游戏设备，或者是为了利用游戏的机制来获取经验或资源。",complexity:"初级",influence:"挂机行为对游戏和其他玩家都有一定的影响，比如，在需要团队合作的游戏中，挂机玩家可能会导致团队人数的失衡，使得其他玩家面临更大的挑战。此外，挂机也可能影响到游戏的经济系统，因为挂机玩家可能会获取到大量的资源或经验，从而破坏游戏的平衡。",avoidances:["A0001","A0010-004","A0015","A0020","A0048","A0059"],references:[{title:"Cheating in video games - Wikipedia",link:"https://en.wikipedia.org/wiki/Cheating_in_video_games"}],updated:"2026-06-11",keywords:["挂机","自动挂机","脚本挂机","离线挂机","自动打怪","按键精灵挂机","Bot挂机"]},n={R0100:t},a=e({R0101:()=>s,default:()=>o}),s={title:"送人头",definition:'指的是玩家故意或者因为操作失误导致自己的游戏角色被对方玩家击杀，也就是给对方送去了一次击杀（被称为"人头〞）的机会。',description:"送人头会直接影响到游戏的结果。在MOBA类游戏中，每次击杀都会给击杀者带来经验和金钱。因此送人头会使对方玩家变得更强，从而影响到团队的战斗力。此外，送人头也可能会影响到其他玩家的游戏体验，因为这可能会导致游戏的失衡，使得他们在游戏中面临更大的困难。",complexity:"初级",influence:"影响游戏公平性及其他玩家体验",avoidances:["A0015","A0048","A0020"],references:[{title:"Cheating in video games - Wikipedia",link:"https://en.wikipedia.org/wiki/Cheating_in_video_games"}],updated:"2026-06-11",keywords:["送人头","故意送头","送头","送分","喂人头"]},o={R0101:s},c=e({R0102:()=>r,default:()=>l}),r={title:"带老板",definition:"是指玩家（老板）加入到开挂的队伍中，与开挂玩家组成一队，在游戏中快速获益。",description:'在不同的游戏中，"带老板"又有不同的叫法，有的叫"坐挂车"，有的叫"坐飞机"。目前"带老板"已经有成熟的商业模式，外挂代理、黑产中介、外挂用户有着明确的分工。',complexity:"初级",influence:"影响游戏公平性及其他玩家体验",avoidances:["A0015","A0048","A0020"],references:[{title:"Video game boosting - Wikipedia",link:"https://en.wikipedia.org/wiki/Video_game_boosting"}],updated:"2026-06-11",keywords:["带老板","坐挂车","坐飞机","老板号","带躺","挂车老板"]},l={R0102:r},d=e({R0103:()=>A,default:()=>p}),A={title:"观战透视",definition:"指的是玩家在游戏小号中使用透视外挂来观战大号的方式进行作弊，通常存在于FPS游戏中。",description:"观战透视基本原理是使用两个账号，一个常用的大号和一个用于观战的小号。大号和小号加为好友后，大号进入游戏的同时小号打开透视辅助观战大号。通过小号的透视功能，大号可以轻松掌握敌人的位置，从而更容易地获得游戏胜利。如果小号被封了后，玩家会重新创建小号继续使用观战透视进行游戏。",complexity:"初级",influence:"这种行为破坏了游戏的公平性，并对其他玩家的游戏体验造成了严重影响",avoidances:["A0010","A0010-004","A0015","A0048","A0059","A0020"],references:[{title:"Cheating in video games - Wikipedia",link:"https://en.wikipedia.org/wiki/Cheating_in_video_games"}],updated:"2026-06-11",keywords:["观战透视","OB透视","观战外挂","小号观战","透视报点","观战报点"]},p={R0103:A},u=e({R0104:()=>f,default:()=>w}),f={title:"护航作弊",definition:"护航作弊是一种在游戏中使用的作弊手段，指的是利用多个账号，通过匹配和老板大号进入同一对局进行保驾护航，以帮助老板大号获得更好的游戏体验和胜率。",description:"主要存在于射击竞技类游戏中，护航的玩家分为两队：一队是上交了保护费的老板玩家（主要目的是上分）、另外一队用高段位大号（司机）组队带上一个开挂的小号（打手）。两队同一时间开启匹配，提高匹配到同一局的概率。司机成功将打手送入高分段对局后便退出游戏，而后打手负责淘汰其他玩家，老板则等待到最后决赛圈击败打手，直接成为冠军。",complexity:"初级",influence:"影响游戏公平性及其他玩家体验",avoidances:["A0010","A0010-004","A0015","A0048","A0059","A0020"],references:[{title:"Cheating in video games - Wikipedia",link:"https://en.wikipedia.org/wiki/Cheating_in_video_games"}],updated:"2026-06-11",keywords:["护航作弊","护航上分","保驾护航","司机打手","同局护航","护航吃鸡"]},w={R0104:f},k=e({R0105:()=>y,default:()=>h}),y={title:"租号借号",definition:"租号借号是一种将账号租借给别人的行为。",description:"这可能涉及社交媒体账号、游戏账号、电子商务账号、支付账号等。租号和借号的行为可能出于各种目的，其中一些可能是合法的，但也存在潜在的风险和非法用途。用途包括但不限于：游戏： 一些玩家可能通过租借他人的游戏账号，以获取账号上的虚拟物品、游戏货币，或是提升账号等级，以获得游戏中的优势。社交媒体： 有些人可能租用或借用社交媒体账号，以增加粉丝数量、提升曝光度，或是进行其他与账号关联的社交活动。电商平台： 在一些电商平台上，人们可能租用或借用账号，进行虚假购物活动、虚构好评，以提高店铺或产品的信誉。广告点击： 一些不法分子可能租用或借用账号，用于进行恶意点击广告的行为，以欺骗广告商获取不正当的收益。",complexity:"初级",influence:"租号借号行为存在一系列潜在风险，包括账号被滥用导致账号所有者受损、欺诈和非法用途可能带来法律责任、违反平台规定可能导致封禁，以及隐私风险可能使个人信息遭受滥用。",avoidances:["A0017","A0033","A0021","A0015","A0026","A0023-001","A0020","A0043"],references:[{title:"Account sharing - Wikipedia",link:"https://en.wikipedia.org/wiki/Account_sharing"}],updated:"2026-06-11",keywords:["租号借号","账号出租","账号外借","租游戏号","借号","号商租号"]},h={R0105:y},m=e({R0106:()=>g,default:()=>I}),g={title:"游戏代练",definition:"游戏代练是指玩家雇佣专业的游戏玩家或团队，代替他们进行游戏，提升游戏账号的等级、获取虚拟物品或完成特定游戏任务。这种服务的目的是帮助玩家在游戏中取得进展，节省时间和精力。",description:"游戏代练通常由技术娴熟的游戏玩家或者公司提供，他们会代替普通玩家玩游戏，以提高玩家账号在游戏中的等级，获取特定的物品、技能或荣誉等，普通玩家通常需要为这种服务付费。当前游戏代练产业发展成熟，网络上各种的代练中介平台和被利益驱动的代练打手越来越多，号主、上游商家、打手、代练平台之间已经形成了一条完整的黑产产业链。",complexity:"初级",influence:"代练可能扰乱游戏环境，使玩家技能看似高于实际水平，影响游戏的公平性和协作性。此外，代练也可能扰乱游戏经济，导致通货膨胀、物品价格上涨，影响正常玩家的体验。同时，代练还涉及账号安全问题，存在被盗取或滥用的风险，可能导致账户被封禁。",avoidances:["A0024","A0021","A0021-001","A0015","A0023-001","A0001-004","A0020"],references:[{title:"Video game boosting - Wikipedia",link:"https://en.wikipedia.org/wiki/Video_game_boosting"}],updated:"2026-06-11",keywords:["游戏代练","代打","上分代练","代肝","刷段位","代练工作室"]},I={R0106:g},R=e({R0107:()=>v,default:()=>S}),v={title:"游戏演员行为",definition:"一般指的在游戏中，存在送分和吃分的玩家，在同一对局中，操纵比赛结果的恶意行为，一般出现在MOBA游戏对局中，有时也会出现在FPS游戏中。",description:"演员基本分布在高段位排位对局，是有组织有计划地人为操纵比赛结果从而达到特定目的的行为，送分和吃分玩家存在利益关系，这是区别于普通的消极游戏行为的一个最大的特点。近年来，随着游戏安全演员检测技术的日益提升，MOBA游戏的演员行为不再像过去一样明目张胆，而是日趋隐蔽。除了传统的吃分送分行为外，还出现了专门针对头部游戏主播或者职业玩家、操纵比赛结果、进而参与博彩外围获利的演员行为。",complexity:"初级",influence:"影响游戏公平性及其他玩家体验",avoidances:["A0015","A0020"],references:[{title:"Elo hell - Wikipedia",link:"https://en.wikipedia.org/wiki/Elo_hell"}],updated:"2026-06-11",keywords:["游戏演员行为","演员局","送分演员","吃分演员","操纵对局","控分"]},S={R0107:v},P=e({R0108:()=>x,default:()=>T}),x={title:"游戏打金",definition:"游戏打金（Gold Farming）是指通过在游戏中获取虚拟货币或虚拟物品，然后将其出售获得真实货币的行为。",description:'也叫"游戏搬砖"。玩家通常会通过不断打游戏中的怪物或者做赚钱的任务来获取虚拟道具和金币，然后将这些虚拟道具或者金币通过拍卖行卖了转化为金钱。在游戏中，打金通常指的是玩家通过在游戏内进行各种活动，例如杀怪、采集、任务等，以获得游戏内的财富、装备等资源，以提升自己在游戏中的竞争力。这些资源通常可以在游戏内进行交易，或者通过特定的渠道转换为现实世界的货币。',complexity:"初级",influence:"影响平台营收。大量的虚拟货币或物品的流通可能破坏游戏内部经济平衡，导致通货膨胀，影响正常玩家的游戏体验。",avoidances:["A0015","A0029-001","A0061"],references:[{title:"Gold farming - Wikipedia",link:"https://en.wikipedia.org/wiki/Gold_farming"}],updated:"2026-06-11",keywords:["游戏打金","打金币","游戏搬砖","搬砖党","金币农场","工作室打金","RMT"]},T={R0108:x},C=e({R0109:()=>b,default:()=>M}),b={title:"越权/未授权访问",definition:"越权（Unauthorized Access）或未授权访问风险指的是在计算机系统或应用程序中，用户或进程以未经授权的方式获取或尝试获取对资源、数据、功能或系统的访问权限。越权一般可分为水平越权（同权限等级用户之间访问他人资源）和垂直越权（低权限用户获取高权限操作能力）两种类型。",description:"这种风险的发生可能是由于弱密码、漏洞利用、缺乏访问控制、配置错误、或者未经授权的系统或应用程序访问等原因。越权攻击通常发生在应用逻辑层面，如通过篡改请求参数访问其他用户的数据（水平越权），或通过低权限账户执行高权限操作（垂直越权）。未授权访问则指在未进行身份认证的情况下即可访问受保护的资源。这些风险可能导致恶意用户、攻击者或非授权人员越过正常的安全控制，访问其无权访问的敏感信息或执行某些操作。",complexity:"初级",influence:"未授权访问可能导致严重的安全问题，包括但不限于数据泄露、隐私侵犯、服务拒绝、系统崩溃等。",avoidances:["A0017","A0018","A0036","A0055","A0056","A0028"],references:[{title:"Privilege escalation - Wikipedia",link:"https://en.wikipedia.org/wiki/Privilege_escalation"},{title:"T1078 Valid Accounts - MITRE ATT&CK",link:"https://attack.mitre.org/techniques/T1078/"}],updated:"2026-06-11",keywords:["越权/未授权访问","越权访问","未授权访问","水平越权","垂直越权","权限绕过","非法访问"]},M={R0109:b},F=e({R0110:()=>D,default:()=>L}),D={title:"平台色情风险",definition:"平台色情风险指的是在线平台或社交媒体上存在的色情内容和相关的安全风险。",description:"这种风险可能包括未经审查的成人内容、淫秽图片、色情广告、以及可能导致用户身心健康问题的不适当或不法内容。造成平台色情风险的原因有多种，主要包括：网络平台的开放性和便利性：网络平台为人们提供了便捷的交流渠道，但同时也为色情内容的传播提供了便利。一些不法分子会利用平台发布、传播色情内容，谋取利益或满足个人欲望。监管不力：一些网络平台缺乏有效的监管措施，导致色情内容在平台上泛滥。同时，由于网络的匿名性，一些用户也会发布和传播色情内容。利益驱动：一些不法分子为了谋取利益，会发布、传播色情内容。此外，一些平台也会通过推广色情内容来吸引用户，从而获取更多的流量和利润。",complexity:"初级",influence:"平台色情风险对在线平台带来多方面的危害，包括内容审核挑战、未成年人保护问题、社交工程和网络钓鱼的潜在威胁，法律合规性的困扰，用户体验和品牌声誉的受损，以及滥用和骚扰的增加。这种风险可能导致用户感到不适，影响品牌信誉，加重平台管理难度，对用户身心健康、未成年人的健康成长和整体在线社区氛围构成负面影响。",avoidances:["A0018","A0024","A0006","A0015","A0048","A0020","A0020-003","A0044"],references:[{title:"网络信息内容生态治理规定",link:"https://www.cac.gov.cn/2019-12/20/c_1578375159509309.htm"}],updated:"2026-06-13",keywords:["平台色情风险","色情内容","涉黄","黄图","成人视频","软色情","招嫖引流"]},L={R0110:D},O=e({R0111:()=>N,default:()=>B}),N={title:"员工违规操作",definition:"员工违规操作风险指的是员工在工作中故意或不慎地违反组织规章制度、政策或法规，从而对企业的安全、合规性和运营产生潜在的威胁。",description:"员工违规操作的场景多种多样，包括未经授权的数据访问、数据泄露、未经授权的软件或设备使用、社交工程和欺诈、违反合规性要求、网络滥用、泄露商业机密、以及不当使用员工权限等。",complexity:"初级",influence:"可能对企业造成严重的负面影响，包括法律责任、经济损失、声誉损害和安全漏洞。",avoidances:["A0024","A0025-004","A0043","A0050","A0051","A0054","A0057","A0010","A0037","A0023","A0059","A0020-002","A0044","A0058","A0017-001"],references:[{title:"MITRE Insider Threat Research",link:"https://insiderthreat.mitre.org/"},{title:"Insider Threat - Wikipedia",link:"https://en.wikipedia.org/wiki/Insider_threat"}],updated:"2026-06-11",keywords:["员工违规操作","内部人风险","内部威胁","员工舞弊","违规操作","内鬼"]},B={R0111:N,"R0111-001":{title:"员工账号共享",definition:"员工在未经授权的情况下分享其账户凭据（例如用户名和密码）给其他人使用",description:"一般包括：密码共享： 员工可能出于方便或协作的目的，将其登录凭据（用户名和密码）分享给同事或其他人员，以便共享资源或执行任务。共享账户： 多人共用同一账户，可能因为节省成本、规遍任务、绕过权限限制等原因，但这违反了账户安全原则。外部共享： 员工可能将公司账户信息泄露给外部人员，例如承包商、合作伙伴或竞争对手，可能是无意间或有意行为。",complexity:"初级",influence:"共享账户增加了未经授权访问的风险，因为不同的用户可能有不同的权限和责任，违规共享使得难以追踪和控制访问。当账户被共享时，追踪到具体执行某项操作的个体变得困难，这可能导致安全事件发生后难以追责。共享账户可能导致对敏感信息的泄露，因为未经授权的用户可能能够访问他们不应该接触的数据。在一些行业或法规中，共享账户可能违反合规性要求，从而导致法律责任和罚款。",avoidances:["A0017","A0007","A0025-004","A0033","A0010","A0021","A0021-001","A0019","A0011","A0012","A0020-002","A0059","A0041"],references:[{title:"Account Sharing - Wikipedia",link:"https://en.wikipedia.org/wiki/Account_sharing"}],updated:"2026-06-11",keywords:["员工账号共享","共享账号","共用账号","账号共用","凭据共享","密码共享"]},"R0111-002":{title:"员工业务级后门",definition:"员工在软件或系统中植入了未经授权的后门，以确保在以后能够绕过正常的上线流程或审查机制直接访问或操控系统",description:"具体场景可能包括：未经授权的远程访问： 研发人员在系统中嵌入远程访问后门，以便能够在系统部署后远程访问和操控系统，而无需正常的身份验证手段。非法数据访问： 研发人员可能设置业务级后门以获取对系统中敏感数据的未经授权访问权，可能包括个人身份信息、财务数据等。恶意功能激活： 后门可能包含激活恶意功能的代码，导致系统在特定条件下执行恶意操作，例如数据破坏、系统崩溃等。不可察觉的存在： 研发人员可能设计业务级后门，使其难以被检测到，以便长时间维持对系统的潜在访问权，这增加了恶意活动的隐蔽性。",complexity:"中级",influence:"影响包括：数据泄露： 可能导致敏感信息泄露，危及个人隐私和组织机密。业务中断： 恶意操控可能导致系统崩溃或业务中断，对组织的正常运作造成严重影响。声誉损害： 一旦业务级后门被揭示，可能导致客户失去信任，影响公司声誉。法律责任： 违法访问或篡改数据的行为可能导致法律责任和法律追究。",avoidances:["A0043","A0051","A0010","A0037","A0019","A0020-002"],references:[{title:"Insider Threat - Wikipedia",link:"https://en.wikipedia.org/wiki/Insider_threat"}],updated:"2026-06-11",keywords:["员工业务级后门","业务后门","逻辑后门","内部后门","人为后门","私留后门"]}},W=e({R0112:()=>_,default:()=>E}),_={title:"办公环境风险",definition:"办公环境业务安全风险涉及到与业务运营相关的各种潜在威胁和危险，这可能对企业的信息、系统、员工和客户数据等方面造成危害。",description:"以下是一些可能的办公环境业务安全风险场景和相关危害：数据泄露： 由于未经授权的访问、内部泄露或网络攻击，企业的敏感信息、客户数据或商业机密可能被泄露。网络攻击： 恶意软件、病毒、勒索软件、网络钓鱼等网络攻击可能导致业务系统的中断、数据损坏或数据盗窃。供应链风险： 不安全的供应链可能引入恶意软件、劣质产品或服务，对企业信息和业务流程构成威胁。社交工程： 攻击者可能通过欺骗手段获取员工敏感信息，例如通过冒充其他员工、欺诈电话或虚假电子邮件。物理安全风险： 未经授权的访问、设备丢失、不安全的设施布局等可能导致办公环境的物理安全风险。",complexity:"初级",influence:"影响包括：经济损失： 数据泄露、网络攻击和其他业务安全风险可能导致企业面临财务损失，包括修复成本、赔偿费用和业务中断造成的收入损失。声誉损害： 数据泄露、网络攻击等事件可能损害企业声誉，降低客户和合作伙伴的信任。法律责任： 数据泄露可能导致法律责任，公司可能面临合规罚款、诉讼和其他法律后果。业务中断： 由于网络攻击或其他安全事件引起的业务中断可能导致公司无法正常运营，影响服务交付和客户满意度。",avoidances:["A0017-001","A0041","A0051","A0052","A0062"],references:[{title:"Physical Security - Wikipedia",link:"https://en.wikipedia.org/wiki/Physical_security"}],updated:"2026-06-11",keywords:["办公环境风险","办公安全","物理安全","办公室安全","场地安全","办公场所风险"]},E={R0112:_,"R0112-001":{title:"自带设备办公风险",definition:"自带设备办公（BYOD，Bring Your Own Device）指的是员工在工作中使用自己的个人设备（如手机、平板电脑、笔记本电脑）进行业务相关的工作。",description:"自带设备办公存在多种潜在风险场景。首先，个人设备通常缺乏企业级的安全措施，可能成为安全漏洞的来源，导致敏感数据泄露。其次，合规性问题可能因难以监管个人设备而加剧，涉及的数据可能不符合法规要求。连接到企业网络的个人设备可能受到病毒和恶意软件的攻击，对整个网络安全构成威胁。企业难以有效地管理和监控各种不同类型的个人设备，从而增加了设备管理难度。最后，员工离职后仍然具有对公司数据的访问权限，可能导致数据泄露和机密信息泄露。",complexity:"初级",influence:"自带设备办公带来了一系列潜在的危害，包括安全漏洞、数据泄露、合规性问题、网络安全威胁、设备管理难题、失去控制权以及员工离职后的访问问题。由于个人设备的安全性无法完全受到企业控制，可能导致敏感信息在设备遗失、盗窃或被攻击时暴露，同时也增加了网络整体的风险。",avoidances:["A0024","A0025-004","A0033","A0050","A0043","A0051","A0054","A0021","A0037","A0029-003","A0060","A0020-002","A0041"],references:[{title:"NIST SP 1800-22: Mobile Device Security: Bring Your Own Device (BYOD)",link:"https://csrc.nist.gov/pubs/sp/1800/22/final"},{title:"Bring Your Own Device - Wikipedia",link:"https://en.wikipedia.org/wiki/Bring_your_own_device"}],updated:"2026-06-11",keywords:["自带设备办公风险","BYOD","自带设备办公","个人设备办公","自有设备接入"]},"R0112-002":{title:"未授权物理访问",definition:"未经授权的物理访问是指未经公司或组织明确批准的情况下，个体或实体进入办公场所、设备区域、数据中心或其他敏感场所的行为。",description:"这种物理访问可能导致潜在的信息安全威胁和风险，涉及以下方面：未授权人员进入办公区域： 攻击者可能冒充员工、访客或承包商，通过社交工程、假冒身份或其他欺骗手段，绕过安保措施，进入公司的办公区域。访客管理不善： 公司未能有效管理访客进入，缺乏必要的访客登记程序和身份验证措施，可能导致未经授权的人员进入公司区域。未经授权的设备连接： 未经授权的员工或访客可能尝试连接其个人设备到公司网络，可能引入恶意软件、间谍软件或其他安全威胁。物理文件和设备访问： 未授权的个体可能访问、复制或窃取办公区域内的物理文件、电脑或其他设备，导致敏感信息的泄露。未经授权的数据中心访问： 对数据中心的未经授权访问可能导致对服务器、存储设备和网络设备的非法操作，从而引发数据泄露或系统破坏。未经授权的机房访问： 企业的机房通常包含关键的IT设备，未经授权的人员进入可能导致设备的非法访问、破坏或数据泄露。",complexity:"初级",influence:"未经授权的物理访问可能带来严重的信息安全危害。攻击者通过冒充员工、访客或承包商的身份，进入办公场所、数据中心或机房，有可能导致机密信息的窃取、篡改或破坏。这种不当的访问行为可能引发数据泄露，使公司业务受到严重损害，同时也可能导致声誉损失、法律责任和财务损失。另外，未经授权的访问可能使恶意软件或恶意设备进入公司网络，为后续攻击铺平道路。",avoidances:["A0017","A0017-001","A0020-002","A0023-001","A0024","A0041","A0051","A0052","A0059","A0062"],references:[{title:"Physical Security - Wikipedia",link:"https://en.wikipedia.org/wiki/Physical_security"}],updated:"2026-06-11",keywords:["未授权物理访问","未经授权进入","尾随进入","物理闯入","门禁绕过","机房闯入"]},"R0112-003":{title:"未授权设备接入",definition:"企业未授权设备接入风险指的是未经批准或未被授权的设备（包括计算机、移动设备、网络设备等）连接到企业网络或系统中，可能导致安全威胁和数据泄露。这些设备可能是员工自带的个人设备、未经授权的硬件、或者恶意设备，它们进入企业网络后可能对信息安全和网络稳定性构成威胁。",description:"以下是一些可能的未授权设备接入的场景和危害：员工带入个人设备： 员工可能将自己的个人电脑、平板电脑或手机连接到企业网络，而未经授权或未采取必要的安全措施。未授权的硬件： 外部人员或供应商可能携带未经授权的硬件设备，试图将其连接到企业网络，以执行未经授权的操作。未经授权的网络设备： 未经授权的网络设备（如路由器、交换机）可能被连接到企业网络，改变网络拓扑或执行潜在的恶意操作。恶意设备： 攻击者可能尝试将恶意设备（如恶意USB设备或网络嗅探器）连接到企业网络，以执行攻击、窃取信息或横向移动。",complexity:"初级",influence:"危害包括：安全威胁： 未授权设备可能引入病毒、恶意软件或其他安全威胁，对企业网络和系统造成危害。数据泄露： 未经授权的设备可能访问、存储或传输敏感信息，导致数据泄露的风险。",avoidances:["A0017-001","A0020-002","A0041","A0051","A0052","A0057","A0062"],references:[{title:"Physical Security - Wikipedia",link:"https://en.wikipedia.org/wiki/Physical_security"}],updated:"2026-06-11",keywords:["未授权设备接入","私接设备","非法接入设备","未知设备接入","非授权终端","外来设备接入"]},"R0112-004":{title:"物理损害与破坏",definition:"企业物理损害与破坏风险指的是企业在物理层面面临的潜在威胁，这可能导致公司设施、财产或基础设施的损害或破坏。这些风险可能来自多种因素，包括自然灾害、人为破坏、盗窃、恐怖袭击等。",description:"以下是一些可能的场景和危害：自然灾害： 地震、火灾、洪水、飓风等自然灾害可能导致企业设施的严重损坏。人为破坏： 恶意破坏、蓄意纵火、破坏性抢劫等行为可能导致企业财产和设备的损害。盗窃和入侵： 盗贼或未经授权的人员可能尝试进入企业设施，盗窃财产或者对设施进行破坏。恐怖袭击： 恐怖分子可能对企业进行恐怖袭击，导致人员伤亡、设施破坏以及运营中断。工业事故： 事故，如火灾、爆炸或泄漏，可能导致企业设施的损坏，同时对员工和周围环境构成威胁。",complexity:"初级",influence:"可能导致：经济损失： 物理损害和破坏会导致企业面临昂贵的修复成本，同时可能导致业务中断，进而引起经济损失。业务中断： 设施的物理损害可能导致业务中断，影响生产和服务提供，损害企业的运营能力。声誉损害： 物理损害和破坏事件可能对企业的声誉造成负面影响，尤其是在公众和客户中。员工安全风险： 物理损害可能威胁员工的安全，导致伤亡或健康问题。",avoidances:["A0017-001","A0051","A0052","A0058","A0062"],references:[{title:"Sabotage - Wikipedia",link:"https://en.wikipedia.org/wiki/Sabotage"}],updated:"2026-06-11",keywords:["物理损害与破坏","设备破坏","恶意破坏","物理破坏","办公设施损坏","蓄意损毁"]},"R0112-005":{title:"监控与窃听",definition:"指的是在企业环境中，由于监控设备或窃听工具的存在，可能导致机密信息泄露、隐私侵犯以及其他潜在的安全问题。这些风险可能来自内部或外部的威胁，包括员工、竞争对手、供应商或其他不法行为的个体或组织。",description:"一些可能的监控与窃听风险场景包括：非法窃听设备： 不法分子可能在企业办公室、会议室或其他敏感区域安装窃听设备，以监听敏感信息的对话或会议。监控摄像头滥用： 公司内部或外部的监控摄像头可能被滥用，用于监视员工或公司内部的活动，侵犯员工的隐私权。电子窃听： 攻击者可能通过远程访问企业通信设备，如电话线路或VoIP系统，进行窃听敏感通信。内部员工泄密： 内部员工可能通过携带录音设备、拍照设备或其他窃听工具，将机密信息记录下来，并泄露给竞争对手或其他恶意方。供应链风险： 在供应链中的第三方供应商或服务提供商可能被黑客攻击，导致窃听设备被引入企业网络或物理环境。",complexity:"初级",influence:"监控与窃听风险的危害包括但不限于：信息泄露： 监听敏感信息或通信可能导致公司的商业机密、策略和其他重要信息泄露。隐私侵犯： 员工或管理层的隐私权可能受到侵犯，特别是在工作场所或企业活动中。声誉损害： 一旦监控或窃听行为曝光，公司的声誉可能受到损害，影响客户和合作伙伴的信任。",avoidances:["A0017-001","A0041","A0044","A0051","A0052","A0062"],references:[{title:"Eavesdropping - Wikipedia",link:"https://en.wikipedia.org/wiki/Eavesdropping"}],updated:"2026-06-11",keywords:["监控与窃听","窃听设备","偷拍","录音窃听","屏幕窥视","针孔摄像头"]},"R0112-006":{title:"无线网络风险",definition:"无线网络风险指的是在使用无线网络（Wi-Fi）时可能面临的潜在威胁和安全问题。由于无线网络的特性，例如信号广播、无线传输，使其更容易受到不同类型的攻击。",description:"以下是一些常见的无线网络风险：未经授权访问： 未经授权的个体可能尝试访问受保护的无线网络，获取网络中的敏感信息或进行其他恶意活动。密码破解： 攻击者可能试图破解无线网络的密码，以获取网络访问权限。弱密码、默认密码或使用不安全的加密算法都可能增加密码被破解的风险。钓鱼攻击： 攻击者可以设置虚假的无线网络，模拟合法网络的名称，引导用户连接并窃取其敏感信息，这被称为钓鱼攻击。中间人攻击： 攻击者可能尝试在用户和访问点之间插入自己，监视或篡改通信流量。这种攻击被称为中间人攻击，可以导致信息泄露和数据篡改。无线干扰： 恶意设备或无意的无线设备可能引起网络干扰，影响正常的通信和连接质量。无线克隆： 攻击者可能克隆合法的无线访问点，使用户连接到恶意的克隆点，从而暴露于安全风险。无线入侵： 攻击者可能试图入侵无线网络的受保护系统，以获取对网络基础设施和关键信息的访问权限。",complexity:"初级",influence:"可能导致敏感信息泄露、中间人攻击造成数据篡改、未经授权的网络访问，以及业务系统中断等安全风险。",avoidances:["A0017","A0017-001","A0018","A0051","A0052"],references:[{title:"Wireless Security - Wikipedia",link:"https://en.wikipedia.org/wiki/Wireless_security"}],updated:"2026-06-11",keywords:["无线网络风险","WiFi安全","钓鱼热点","伪造热点","弱口令WiFi","无线嗅探"]}},V=e({R0113:()=>G,default:()=>j}),G={title:"恶意拉人头",definition:"利用游戏中的通联渠道，通过各种花言巧语将玩家引诱到其他游戏平台上",description:'恶意拉人的始作俑者会先熟悉目标游戏的相关玩法及游戏流程（俗称"踩点"）；在把玩游戏一段时长后，解锁类似创建工会的功能并拥有一定游戏战力；将目标游戏玩家拉进工会，并在工会公告板里以工会成员必须加入微信群的名义，让成员加下其微信号，然后由其拉入一个"工会微信群"（甚至会多次发邮件信息进行提醒）；在微信群里临时起意，挥斥方遒！诉说些自己大胆的想法，热心地为大家推荐一些国战、仙侠、传奇的游戏给大家，并动员大家进行新区备战！',complexity:"初级",influence:"导致平台玩家流失",avoidances:["A0006","A0015","A0020-003","A0024","A0044","A0048"],references:[{title:"黑灰产,现代人叫野路子,老一辈也叫捞偏门",link:"https://www.meipian.cn/57uw5xm6"}],updated:"2026-06-11",keywords:["恶意拉人头","游戏拉人","挖玩家","导流拉人","跨游导流","公会拉人"]},j={R0113:G},z=e({R0114:()=>U,default:()=>q}),U={title:"游戏仓库号",definition:"游戏仓库号是指在游戏中用于存放游戏物品、装备等的账号。这些账号通常只用于存放物品，不用于实际的游戏操作。游戏仓库号可以是玩家自己的小号，也可以是其他人的账号。",description:"一般黑灰产建设和使用游戏仓库号的方法可能包括以下几个方面：非法获取游戏账号和密码：黑灰产可能会利用各种手段非法获取游戏账号和密码，例如通过木马病毒、钓鱼网站等。这些账号和密码被用于登录游戏仓库号并进行相关操作。使用外挂或插件：有些游戏可能存在外挂或插件，这些工具可以帮助玩家更快地获得胜利或者进行其他违规操作。黑灰产可能会使用这些工具来绕过游戏的限制，从而获取更多的游戏资源。利用漏洞或缺陷：有些游戏可能存在漏洞或者缺陷，这些漏洞可以被黑客或者其他犯罪分子利用来进行攻击或者盗窃游戏账号等行为。因此，游戏运营商需要定期对游戏进行安全检测和修复，以减少漏洞和缺陷的存在。欺骗或者其他非法手段获取游戏资源：黑灰产可能会利用各种欺骗或者其他非法手段来获取游戏资源，例如通过虚假交易、欺诈等方式骗取游戏货币或者装备等。联合其他玩家进行作弊或者违规行为：有些黑灰产组织会联合其他玩家一起进行作弊或者违规行为，以提高作弊的成功率和效果。这种行为不仅会影响其他玩家的游戏体验，也会破坏游戏的公平性和信任度。",complexity:"初级",influence:"破坏游戏经济平衡：如果游戏仓库号被用于大量存放游戏物品、装备等，可能会导致游戏内的经济体系受到破坏。这可能会导致游戏内的物价失衡，影响其他玩家的游戏体验和利益。影响游戏声誉和口碑：如果游戏仓库号被用于进行欺诈、恶意攻击等行为，可能会对游戏的声誉和口碑造成负面影响，从而影响游戏的用户数量和收入。降低用户体验：如果游戏仓库号被用于进行恶意行为，如刷屏、刷道具等，可能会影响其他玩家的游戏体验，降低游戏的可玩性和乐趣。",avoidances:["A0007","A0015","A0024","A0043","A0059","A0010","A0029-001","A0020-003","A0061"],references:[{title:"Gold Farming - Wikipedia",link:"https://en.wikipedia.org/wiki/Gold_farming"},{title:"Real-Money Trading - Wikipedia",link:"https://en.wikipedia.org/wiki/Real-money_trading"}],updated:"2026-06-11",keywords:["游戏仓库号","仓库号","仓库小号","打金仓库号","资源中转号","物资仓库号"]},q={R0114:U},H=e({R0115:()=>Q,default:()=>K}),Q={title:"恶意广告投放",definition:"恶意广告投放是指通过一系列欺诈、欺骗或有害的手段，将恶意内容或虚假宣传投放到广告平台上的行为。",description:"欺诈广告： 投放虚假或欺诈性广告，可能包括虚假商品宣传、虚假承诺，以骗取用户信任或财产。恶意软件传播： 在广告中植入恶意代码或链接，以传播恶意软件、病毒或进行网络攻击。广告欺骗： 利用虚假广告手段，如虚假的广告内容或图像，误导用户点击或进行其他操作。",complexity:"初级",influence:"用户欺骗： 用户可能因为恶意广告而受到欺骗，导致购买虚假或低质量的产品，产生经济损失。品牌声誉受损： 品牌可能因为与恶意广告有关联而受损，失去用户信任，影响长期的品牌声誉。网络安全威胁： 恶意广告可能引发网络安全威胁，包括恶意软件感染、信息泄露等问题。经济损失： 恶意广告活动可能导致品牌和广告平台的经济损失，同时对整体广告生态产生不利影响。法律责任： 违反广告法规和隐私法规，可能导致法律责任和罚款。",avoidances:["A0006","A0006-001","A0006-002","A0006-003","A0006-004","A0006-005","A0006-007","A0006-008","A0020","A0020-001","A0020-003","A0043","A0044","A0047","A0048","A0057"],references:[{title:"Malvertising - Wikipedia",link:"https://en.wikipedia.org/wiki/Malvertising"}],updated:"2026-06-11",keywords:["恶意广告投放","恶意投放","虚假广告","黑五类广告","广告欺诈","恶意导流广告","malvertising"]},K={R0115:Q},X=e({R0116:()=>Y,default:()=>J}),Y={title:"AI深度伪造风险",definition:"利用AI深度伪造（Deepfake）技术生成虚假的人脸图像、视频或音频，用于身份冒充、欺诈、舆论操纵等恶意目的的风险。",description:"AI深度伪造风险是指攻击者利用生成对抗网络（GAN）、扩散模型等AI技术，生成高度逼真的虚假人脸图像、视频或音频内容，用于实施各类欺诈和攻击行为。主要风险场景包括：①身份冒充：利用深度伪造技术伪造他人面部特征，绕过人脸识别认证系统，实施账号盗取、金融欺诈等。②视频通话欺诈：在实时视频通话中使用AI换脸技术冒充他人身份，进行社交工程攻击。③虚假证据制造：生成虚假的视频或音频证据，用于敲诈勒索、名誉损害或法律纠纷。④舆论操纵：制作公众人物的虚假视频，传播虚假信息，影响公众舆论。随着深度伪造技术的快速发展和开源工具的普及，攻击门槛持续降低，已成为业务安全领域的重大新兴威胁。",complexity:"高级",influence:"可导致身份认证体系被突破、金融欺诈损失、品牌声誉严重受损、社会信任危机，以及法律合规风险",avoidances:["A0064","A0066","A0024","A0023","A0023-001","A0007","A0048","A0084","A0088"],references:[{title:"深度伪造技术治理白皮书 - 中国信通院",link:"http://www.caict.ac.cn/"},{title:"Deepfakes and the New Disinformation War",link:"https://www.foreignaffairs.com/articles/world/2018-12-11/deepfakes-and-new-disinformation-war"}],updated:"2026-06-11",keywords:["AI深度伪造风险","深度伪造","Deepfake","AI伪造","深伪","合成音视频"]},J={R0116:Y,"R0116-001":{title:"AI换脸欺诈",definition:"利用AI换脸技术在实时视频或图片中替换人脸，冒充他人身份实施欺诈的行为。",description:"AI换脸欺诈是深度伪造风险中最常见的攻击形式。攻击者利用DeepFaceLab等工具，基于目标人物的公开照片或视频素材训练换脸模型，然后在实时视频通话或录制视频中将自己的面部替换为目标人物。典型攻击场景包括：冒充企业高管进行视频会议诈骗（CEO Fraud）、冒充亲友进行视频通话骗取钱财、伪造人脸通过远程身份认证（如银行开户、贷款审批）等。2024年以来，多起利用AI换脸进行的大额诈骗案件被曝光，单笔损失金额可达数千万元。",complexity:"高级",influence:"直接导致金融欺诈损失、身份认证体系失效、用户信任危机",avoidances:["A0066","A0023","A0023-001","A0048","A0007"],references:[{title:"AI换脸诈骗案例分析",link:"https://www.mps.gov.cn/"}],updated:"2026-06-11",keywords:["AI换脸欺诈","AI换脸","换脸诈骗","视频换脸","实时换脸","刷脸冒充"]},"R0116-002":{title:"AI合成视频欺诈",definition:"利用AI技术合成虚假视频内容，用于虚假宣传、舆论操纵或欺诈的行为。",description:"AI合成视频欺诈是指利用深度伪造技术生成完整的虚假视频内容，包括虚假的新闻报道、产品推荐、名人代言等。与AI换脸不同，合成视频可能涉及全身合成、场景合成等更复杂的技术。攻击者可以利用合成视频进行虚假广告投放、伪造名人代言推广诈骗产品、制作虚假新闻影响股价等。",complexity:"高级",influence:"导致虚假信息传播、消费者被误导、品牌声誉受损、市场秩序混乱",avoidances:["A0064","A0066","A0006","A0006-001","A0020","A0048"],references:[{title:"Deepfake - Wikipedia",link:"https://en.wikipedia.org/wiki/Deepfake"}],updated:"2026-06-11",keywords:["AI合成视频欺诈","合成视频诈骗","深伪视频","伪造视频","数字人伪造视频","名人代言伪造"]}},Z=e({R0117:()=>$,default:()=>ee}),$={title:"LLM提示注入风险",definition:"针对集成了大语言模型（LLM）的业务系统，通过精心构造的提示词（Prompt）来操纵模型行为，使其执行非预期操作的风险。",description:"LLM提示注入风险是随着大语言模型在业务系统中广泛应用而出现的新型安全风险。攻击者通过在输入中嵌入恶意指令，试图覆盖或绕过系统预设的提示词约束，使模型泄露敏感信息、执行未授权操作或生成有害内容。提示注入攻击已被OWASP列为LLM应用的头号安全风险。主要攻击方式包括直接提示注入和间接提示注入两大类。",complexity:"高级",influence:"可导致敏感数据泄露、业务逻辑被绕过、系统被操纵执行未授权操作、生成有害或违规内容",avoidances:["A0065","A0087","A0002","A0004","A0015","A0032"],references:[{title:"OWASP Top 10 for LLM Applications",link:"https://owasp.org/www-project-top-10-for-large-language-model-applications/"},{title:"Prompt Injection攻击与防御综述",link:"https://arxiv.org/abs/2310.12397"}],updated:"2026-06-10",keywords:["LLM提示注入风险","提示注入","Prompt Injection","系统提示词绕过","越狱提示","提示攻击"]},ee={R0117:$,"R0117-001":{title:"直接提示注入",definition:"攻击者直接在用户输入中嵌入恶意指令，试图覆盖系统提示词或操纵模型行为。",description:"直接提示注入是指攻击者在与LLM交互时，直接在输入文本中嵌入恶意指令来操纵模型行为。常见手法包括：角色扮演攻击（要求模型扮演不受限制的角色）、指令覆盖（使用'忽略之前的指令'等话术）、编码绕过（使用Base64、Unicode等编码方式隐藏恶意指令）、多语言混合（利用不同语言的指令混淆模型）等。",complexity:"中级",influence:"模型行为被操纵，可能泄露系统提示词、生成违规内容或执行未授权操作",avoidances:["A0065","A0087","A0004","A0015"],references:[{title:"OWASP Top 10 for LLM Applications",link:"https://owasp.org/www-project-top-10-for-large-language-model-applications/"}],updated:"2026-06-10",keywords:["直接提示注入","Direct Prompt Injection","忽略之前的指令","角色扮演越狱","提示词覆盖"]},"R0117-002":{title:"间接提示注入",definition:"攻击者将恶意指令隐藏在模型可能检索或处理的外部数据源中，间接操纵模型行为。",description:"间接提示注入是一种更隐蔽的攻击方式，攻击者不直接与模型交互，而是将恶意指令嵌入到模型可能访问的外部数据源中，如网页内容、文档、邮件、数据库记录等。当LLM应用在处理这些外部数据时，隐藏的恶意指令会被模型执行。例如，在RAG（检索增强生成）系统中，攻击者可以在知识库文档中植入恶意指令；在AI邮件助手场景中，攻击者可以在邮件正文中嵌入操纵指令。间接提示注入的危害更大，因为它可以在用户不知情的情况下触发。",complexity:"高级",influence:"可在用户不知情的情况下操纵模型行为，导致数据泄露、未授权操作等严重后果",avoidances:["A0065","A0087","A0003","A0015","A0032"],references:[{title:"Indirect Prompt Injection Threats",link:"https://arxiv.org/abs/2302.12173"}],updated:"2026-06-10",keywords:["间接提示注入","Indirect Prompt Injection","RAG投毒","文档投毒","网页提示注入","知识库投毒"]}},ie=e({R0118:()=>te,default:()=>ne}),te={title:"AI自动化攻击升级",definition:"利用AI技术（特别是大语言模型）来自动化、增强和规模化传统网络攻击和业务攻击的风险。",description:"AI自动化攻击升级是指攻击者利用AI技术大幅提升传统攻击的效率、规模和成功率。主要表现包括：①AI辅助社工攻击：利用LLM自动生成高度个性化的钓鱼邮件和社工话术，大幅提高钓鱼成功率。②AI辅助漏洞利用：利用AI自动发现和利用安全漏洞，加速攻击链的构建。③智能验证码破解：利用多模态AI模型自动识别和破解各类验证码。④自适应攻击：AI驱动的攻击工具可以根据防御策略自动调整攻击方式，实现攻防对抗的自动化。⑤批量内容生成：利用AI批量生成虚假评论、虚假账号资料等，支撑大规模业务欺诈。AI技术的引入使得攻击的技术门槛大幅降低，攻击成本显著下降，而攻击效果却大幅提升。",complexity:"高级",influence:"传统安全防护体系面临严峻挑战，攻击规模和效率大幅提升，防御成本显著增加",avoidances:["A0065","A0087","A0001","A0004","A0067","A0008","A0015","A0064"],references:[{title:"OWASP Top 10 for Large Language Model Applications",link:"https://owasp.org/www-project-top-10-for-large-language-model-applications/"},{title:"NCSC: The near-term impact of AI on the cyber threat",link:"https://www.ncsc.gov.uk/report/impact-of-ai-on-cyber-threat"}],updated:"2026-06-13",keywords:["AI自动化攻击升级","AI攻击自动化","AI辅助攻击","自动化社工","智能钓鱼","AI批量攻击"]},ne={R0118:te},ae=e({R0119:()=>se,default:()=>oe}),se={title:"AI生成虚假评论",definition:"利用AI技术（特别是大语言模型）批量生成虚假的商品评论、服务评价或内容评论，扰乱平台评价体系的风险。",description:"AI生成虚假评论是指攻击者利用大语言模型批量生成看似真实的虚假评论内容。与传统的人工刷评相比，AI生成的评论具有以下特点：①内容多样性高：每条评论的措辞、角度、风格各不相同，难以通过简单的文本相似度检测发现。②生成成本极低：利用LLM可以在极短时间内生成大量高质量评论，成本远低于人工撰写。③针对性强：可以根据商品特征、竞品信息等自动生成有针对性的好评或差评。④多语言支持：可以轻松生成多种语言的评论，支持跨境电商场景的刷评。这种风险严重影响平台评价体系的公信力，误导消费者决策，破坏公平竞争环境。",complexity:"中级",influence:"平台评价体系公信力下降、消费者被误导、公平竞争环境被破坏、平台合规风险增加",avoidances:["A0064","A0006","A0006-008","A0020","A0029","A0029-001","A0043","A0048"],references:[{title:"AI生成虚假评论检测研究",link:"https://arxiv.org/abs/2306.07401"}],updated:"2026-06-11",keywords:["AI生成虚假评论","AI刷评","机器生成评论","虚假好评","评论农场","AIGC刷评论"]},oe={R0119:se},ce=e({R0120:()=>re,default:()=>le}),re={title:"AI语音克隆欺诈",definition:"利用AI语音克隆技术伪造他人声音，实施电话诈骗、绕过声纹认证或制造虚假音频证据的风险。",description:"AI语音克隆欺诈是指攻击者利用深度学习语音合成技术，基于少量目标人物的语音样本（甚至仅需几秒钟的录音），即可生成与目标人物高度相似的合成语音。主要风险场景包括：①电话诈骗：冒充亲友、领导或客服人员的声音进行电话诈骗，骗取转账或敏感信息。②声纹认证绕过：利用克隆语音绕过银行、支付平台等的声纹认证系统。③虚假音频证据：制作虚假的通话录音或语音消息，用于敲诈勒索或法律纠纷。④社交工程增强：结合AI语音克隆和深度伪造视频，实施更具欺骗性的社交工程攻击。随着零样本语音克隆技术的成熟，攻击者甚至可以从社交媒体上公开的语音内容中提取足够的样本。",complexity:"高级",influence:"导致电话诈骗成功率大幅提升、声纹认证体系失效、用户财产损失和信任危机",avoidances:["A0066","A0023","A0023-001","A0073","A0007","A0027"],references:[{title:"AI语音克隆诈骗案例 - FBI",link:"https://www.ic3.gov/"},{title:"语音深度伪造检测技术综述",link:"https://arxiv.org/abs/2308.14970"}],updated:"2026-06-11",keywords:["AI语音克隆欺诈","语音克隆诈骗","AI拟声","声纹冒充","声音合成诈骗","声纹绕过"]},le={R0120:re},de=e({R0121:()=>Ae,default:()=>pe}),Ae={title:"虚拟货币洗钱风险",definition:"利用加密货币的匿名性和去中心化特性，通过混币、跨链转账等手段进行洗钱活动的风险。",description:"虚拟货币洗钱风险是指犯罪分子利用比特币、以太坊等加密货币进行资金清洗的行为。主要手法包括：①混币服务：通过Tornado Cash等混币器混淆资金流向，切断交易链路的可追溯性。②跨链桥转移：利用跨链桥将资金在不同区块链之间转移，增加追踪难度。③去中心化交易所（DEX）：通过DEX进行无KYC的代币兑换，规避中心化交易所的反洗钱审查。④隐私币：使用Monero、Zcash等隐私币进一步隐匿交易信息。⑤NFT洗钱：通过虚假的NFT交易实现资金转移。⑥OTC场外交易：通过场外交易将加密货币兑换为法币。这种风险对金融平台、支付平台和电商平台都构成严重威胁，尤其是涉及虚拟商品交易的场景。",complexity:"高级",influence:"平台面临反洗钱合规风险、监管处罚、声誉损失，可能被犯罪分子利用为洗钱通道",avoidances:["A0016","A0016-001","A0029","A0029-001","A0015","A0044","A0054"],references:[{title:"AML Issues in Cryptocurrency and Blockchain Technology",link:"https://www.bloomberglaw.com/external/document/XB8LV1T4000000/banking-professional-perspective-aml-issues-in-cryptocurrency-an"},{title:"虚拟货币反洗钱监管趋势",link:"http://www.pbc.gov.cn/"}],updated:"2026-06-11",keywords:["虚拟货币洗钱风险","加密货币洗钱","混币","跨链洗钱","链上洗钱","洗币"]},pe={R0121:Ae},ue=e({R0122:()=>fe,default:()=>we}),fe={title:"NFT欺诈风险",definition:"利用NFT（非同质化代币）市场的不透明性和监管空白，实施虚假交易、价格操纵、知识产权侵权等欺诈行为的风险。",description:"NFT欺诈风险涵盖多种欺诈形式：①洗售交易（Wash Trading）：同一人或关联方之间反复交易同一NFT，人为抬高价格和交易量，制造虚假繁荣。②拉高出货（Rug Pull）：项目方在NFT发售后卷款跑路，购买者的投资血本无归。③知识产权侵权：未经授权将他人的艺术作品、品牌标识等铸造为NFT进行销售。④虚假项目：创建虚假的NFT项目，通过虚假宣传和社区炒作吸引投资者。⑤钓鱼攻击：通过伪造的NFT交易平台或钱包连接请求窃取用户的加密资产。⑥元数据篡改：在NFT铸造后修改其关联的数字资产内容。",complexity:"中级",influence:"投资者财产损失、知识产权被侵犯、市场信任度下降、平台合规风险",avoidances:["A0016","A0015","A0006","A0024","A0044","A0043"],references:[{title:"NFT市场欺诈分析 - Chainalysis",link:"https://www.chainalysis.com/"}],updated:"2026-02-27",keywords:["NFT欺诈风险","NFT诈骗","洗盘交易","拉地毯","虚假NFT项目","NFT盗图"]},we={R0122:fe},ke=e({R0123:()=>ye,default:()=>he}),ye={title:"算法合规风险",definition:"企业使用的算法系统（推荐算法、定价算法、风控算法等）不符合算法透明性、公平性和可解释性等监管要求的风险。",description:"算法合规风险是指企业在使用算法进行业务决策时，可能违反相关法律法规的风险。随着《互联网信息服务算法推荐管理规定》《生成式人工智能服务管理暂行办法》等法规的出台，算法合规要求日益严格。主要风险包括：①算法歧视：推荐算法、定价算法等对不同用户群体产生不公平的差异化对待。②信息茧房：推荐算法过度个性化导致用户信息获取面窄化，影响信息多样性。③算法不透明：用户无法了解影响其权益的算法逻辑，缺乏知情权和选择权。④算法操纵：利用算法操纵搜索排名、信息流排序等，影响市场公平竞争。⑤未备案风险：具有舆论属性或社会动员能力的算法推荐服务未按规定进行算法备案。",complexity:"中级",influence:"面临监管处罚、罚款、业务整改要求，以及用户信任度下降和声誉损失",avoidances:["A0072","A0054","A0052","A0043"],references:[{title:"互联网信息服务算法推荐管理规定",link:"https://www.cac.gov.cn/2022-01/04/c_1642894606364259.htm"},{title:"生成式人工智能服务管理暂行办法",link:"https://www.cac.gov.cn/2023-07/13/c_1690898327029107.htm"}],updated:"2026-06-11",keywords:["算法合规风险","算法推荐合规","推荐算法备案","算法歧视","算法透明性","可解释性不足"]},he={R0123:ye},me=e({R0124:()=>ge,default:()=>Ie}),ge={title:"未成年人保护合规风险",definition:"平台在未成年人保护方面未能满足日益严格的法律法规要求，包括内容分级、使用时长限制、消费限制、隐私保护等方面的合规风险。",description:"未成年人保护合规风险是指互联网平台在保护未成年用户方面面临的合规挑战。随着《未成年人网络保护条例》等法规的实施，平台需要在以下方面满足合规要求：①实名认证与年龄验证：准确识别未成年用户身份，防止未成年人绕过年龄限制。②使用时长管理：实施青少年模式，限制未成年人的使用时长和使用时段。③内容分级与过滤：对平台内容进行分级管理，屏蔽不适合未成年人的内容。④消费限制：限制未成年人的充值和消费金额，防止非理性消费。⑤隐私保护：对未成年人的个人信息实施更严格的保护措施。⑥防沉迷机制：建立有效的防沉迷系统，防止未成年人过度使用。⑦家长监护：提供家长监护工具和功能。",complexity:"中级",influence:"面临监管处罚、业务整改、社会舆论压力，以及未成年人权益受损的法律责任",avoidances:["A0046","A0023","A0054","A0043","A0006","A0009"],references:[{title:"未成年人网络保护条例",link:"https://www.gov.cn/zhengce/content/202310/content_6911288.htm"},{title:"...犯罪、强制报告等热点问题,最高检发布10起涉未成年人典型案例",link:"https://lnsfnlhh.cn/lnsfnlhh/wqfw/flfg/2026052818575315702/"}],updated:"2026-06-11",keywords:["未成年人保护合规风险","青少年模式","防沉迷","未成年充值","未成年人内容保护","适龄分级"]},Ie={R0124:ge},Re=e({R0125:()=>ve,default:()=>Se}),ve={title:"跨境电商合规风险",definition:"跨境电商业务在不同国家和地区的法律法规、税务政策、数据保护要求等方面面临的合规风险。",description:"跨境电商合规风险是指企业在开展跨境电商业务时，需要同时遵守多个国家和地区的法律法规，面临的合规挑战。主要风险包括：①数据跨境传输：不同国家对个人数据跨境传输有不同的限制要求，如欧盟GDPR、中国《数据出境安全评估办法》等。②税务合规：各国对跨境电商的税收政策不同，包括增值税、关税、数字服务税等。③产品合规：不同市场对产品安全标准、认证要求、标签规范等存在差异。④消费者权益保护：各国消费者保护法律对退换货、售后服务、广告宣传等有不同要求。⑤知识产权：跨境销售可能涉及不同法域的知识产权侵权风险。⑥支付合规：跨境支付涉及外汇管理、反洗钱等合规要求。⑦平台责任：各国对电商平台的责任界定和监管要求不同。",complexity:"中级",influence:"面临多国监管处罚、市场准入限制、罚款、业务中断，以及声誉损失",avoidances:["A0054","A0043","A0035","A0035-001","A0016","A0052"],references:[{title:"跨境电商合规白皮书",link:"http://www.mofcom.gov.cn/"},{title:"EU Digital Services Act",link:"https://digital-strategy.ec.europa.eu/en/policies/digital-services-act-package"}],updated:"2026-06-11",keywords:["跨境电商合规风险","跨境电商合规","数据跨境","GDPR","VAT合规","海外商品合规","DSA合规"]},Se={R0125:ve},Pe=e({R0126:()=>xe,default:()=>Te}),xe={title:"API滥用风险",definition:"攻击者通过发现、枚举和滥用业务系统的API接口，实施数据窃取、业务逻辑绕过、资源耗尽等攻击的风险。",description:"API滥用风险是随着微服务架构和API经济的发展而日益突出的安全风险。攻击者通过各种手段发现和利用API接口的安全缺陷，实施恶意操作。主要风险场景包括API枚举攻击、API速率限制绕过和API业务逻辑滥用等。",complexity:"中级",influence:"敏感数据泄露、业务逻辑被绕过、服务可用性受影响、经济损失",avoidances:["A0067","A0004","A0002","A0008","A0015","A0017"],references:[{title:"OWASP API Security Top 10 2023",link:"https://owasp.org/API-Security/editions/2023/en/0x11-t10/"},{title:"永安在线API安全研究报告(2022年Q1)|浏览器_网易订阅",link:"https://www.163.com/dy/article/H5Q1LC3R0518STKV.html"}],updated:"2026-06-11",keywords:["API滥用风险","API abuse","接口滥用","接口盗刷","接口攻击","业务接口滥用"]},Te={R0126:xe,"R0126-001":{title:"API枚举攻击",definition:"通过自动化工具发现和枚举目标系统的API端点，获取未授权的API接口信息。",description:"API枚举攻击是指攻击者通过路径爆破、Swagger/OpenAPI文档泄露、JavaScript代码分析、流量分析等手段，发现目标系统暴露的API端点。攻击者可能发现未经保护的管理接口、测试接口、废弃但未下线的旧版本接口等，进而利用这些接口获取敏感数据或执行未授权操作。",complexity:"中级",influence:"暴露系统内部接口信息，为后续攻击提供入口",avoidances:["A0067","A0004","A0032","A0017"],references:[{title:"OWASP API Security Top 10 2023",link:"https://owasp.org/API-Security/editions/2023/en/0x11-t10/"}],updated:"2026-06-11",keywords:["API枚举攻击","接口枚举","端点枚举","API探测","路径爆破","Swagger泄露"]},"R0126-002":{title:"API速率限制绕过",definition:"通过技术手段绕过API接口的速率限制（Rate Limiting）机制，实现超频调用。",description:"API速率限制绕过是指攻击者通过IP轮换、分布式请求、参数变异、Header伪造、利用不同API版本等手段，绕过API接口设置的速率限制。绕过速率限制后，攻击者可以进行暴力破解、批量数据爬取、资源耗尽攻击等。",complexity:"高级",influence:"速率限制防护失效，系统面临暴力破解、数据爬取、资源耗尽等风险",avoidances:["A0067","A0004","A0008","A0038"],references:[{title:"OWASP API4:2023 Unrestricted Resource Consumption",link:"https://owasp.org/API-Security/editions/2023/en/0xa4-unrestricted-resource-consumption/"}],updated:"2026-06-11",keywords:["API速率限制绕过","接口限流绕过","Rate Limit Bypass","刷接口","频控绕过","限频绕过"]},"R0126-003":{title:"API业务逻辑滥用",definition:"利用API接口的业务逻辑缺陷，通过合法的API调用实现非预期的业务操作。",description:"API业务逻辑滥用是指攻击者通过分析API的业务逻辑，利用接口设计中的逻辑缺陷实施攻击。例如：通过修改API请求参数绕过价格校验、利用API调用顺序的漏洞跳过支付流程、通过批量API调用实现库存锁定、利用API的并发处理缺陷实现条件竞争等。这类攻击使用的都是合法的API调用，传统的安全防护手段难以检测。",complexity:"高级",influence:"业务逻辑被绕过，可能导致经济损失、数据不一致、业务流程被破坏",avoidances:["A0067","A0015","A0002","A0014"],references:[{title:"OWASP API6:2023 Unrestricted Access to Sensitive Business Flows",link:"https://owasp.org/API-Security/editions/2023/en/0xa6-unrestricted-access-to-sensitive-business-flows/"}],updated:"2026-06-11",keywords:["API业务逻辑滥用","接口逻辑漏洞","业务流滥用","业务接口绕过","敏感业务流滥用","参数篡改下单"]}},Ce=e({R0127:()=>be,default:()=>Me}),be={title:"供应链投毒风险",definition:"攻击者通过在软件供应链的各个环节植入恶意代码或后门，影响下游用户和系统安全的风险。",description:"供应链投毒风险是指攻击者通过污染软件供应链来实施大规模攻击。主要攻击方式包括：①开源组件投毒：在npm、PyPI、Maven等包管理平台上发布包含恶意代码的软件包，或通过Typosquatting（名称相似的恶意包）欺骗开发者安装。②依赖混淆攻击：利用包管理器的依赖解析机制，使目标系统安装攻击者控制的恶意包。③构建环境污染：入侵CI/CD管道，在构建过程中注入恶意代码。④上游项目劫持：获取热门开源项目的维护权限后植入后门。⑤商业软件后门：在商业软件的更新包中植入恶意代码（如SolarWinds事件）。近年来供应链攻击事件频发，影响范围广泛，已成为最具威胁的攻击方式之一。",complexity:"高级",influence:"影响范围极广，可导致大量下游系统被植入后门、敏感数据泄露、业务中断",avoidances:["A0070","A0055","A0054","A0052","A0013","A0014"],references:[{title:"软件供应链安全白皮书 - 中国信通院",link:"http://www.caict.ac.cn/"},{title:"SLSA: Supply-chain Levels for Software Artifacts",link:"https://slsa.dev/"}],updated:"2026-02-27",keywords:["供应链投毒风险","软件供应链投毒","依赖投毒","包投毒","开源投毒","恶意依赖包"]},Me={R0127:be},Fe=e({R0128:()=>De,default:()=>Le}),De={title:"云原生安全风险",definition:"在云原生架构（容器、Kubernetes、微服务、Serverless等）环境中，由于配置不当、权限管理缺陷等导致的安全风险。",description:"云原生安全风险是指企业在采用云原生技术栈时面临的特有安全挑战。主要风险包括：①容器逃逸：攻击者利用容器运行时的漏洞突破容器隔离，获取宿主机权限。②Kubernetes配置不当：RBAC权限过大、API Server未认证暴露、etcd未加密、Pod安全策略缺失等。③镜像安全：使用包含已知漏洞或恶意代码的容器镜像。④服务网格安全：微服务间通信的认证和加密不足。⑤Serverless安全：函数权限过大、事件注入、依赖库漏洞等。⑥云配置漏洞：存储桶公开访问、安全组规则过于宽松、IAM权限过大等。⑦密钥管理：硬编码的密钥、未轮换的凭证、密钥存储不当等。",complexity:"高级",influence:"可导致大规模数据泄露、服务中断、横向移动攻击、云资源被滥用",avoidances:["A0071","A0068","A0085","A0055","A0041","A0017","A0052"],references:[{title:"OWASP Kubernetes Top 10",link:"https://owasp.org/www-project-kubernetes-top-ten/"},{title:"云原生安全白皮书 - CNCF",link:"https://www.cncf.io/reports/cloud-native-security-whitepaper/"}],updated:"2026-06-11",keywords:["云原生安全风险","Kubernetes安全","K8s安全","容器安全","镜像安全","Serverless安全"]},Le={R0128:De},Oe=e({R0129:()=>Ne,default:()=>Be}),Ne={title:"短信轰炸即服务",definition:"利用商业化的短信轰炸服务平台，对目标手机号码发送大量垃圾短信，造成骚扰或消耗短信资源的风险。",description:"短信轰炸即服务（SMS Bombing as a Service）是指黑产团伙将短信轰炸能力封装为在线服务，任何人只需支付少量费用即可对指定手机号码发起短信轰炸攻击。攻击者通过收集大量网站和App的短信验证码接口，利用这些接口向目标号码批量发送验证码短信。主要危害包括：①用户骚扰：目标用户在短时间内收到大量垃圾短信，严重影响正常使用。②短信资源消耗：被滥用的平台需要承担大量短信发送费用。③验证码接口滥用：平台的短信验证码接口被恶意调用，影响正常业务。④掩护攻击：通过大量垃圾短信掩盖真正的安全告警短信（如登录通知、交易确认等）。",complexity:"初级",influence:"用户被骚扰、平台短信资源被消耗、验证码接口被滥用、安全告警被淹没",avoidances:["A0004","A0001","A0016","A0016-003","A0044","A0067"],references:[{title:"短信轰炸攻击分析与防御",link:"https://www.freebuf.com/"}],updated:"2026-06-11",keywords:["短信轰炸即服务","短信轰炸","SMS Bombing","轰炸平台","短信炸弹","验证码轰炸"]},Be={R0129:Ne},We=e({R0130:()=>_e,default:()=>Ee}),_e={title:"数字人直播欺诈",definition:"利用AI数字人技术进行虚假直播带货、冒充真人主播或进行其他直播欺诈行为的风险。",description:"数字人直播欺诈是指利用AI生成的虚拟数字人进行直播活动中的欺诈行为。主要风险场景包括：①虚假直播带货：使用AI数字人冒充真人主播进行24小时不间断直播带货，销售假冒伪劣商品或进行虚假宣传。②名人冒充：利用深度伪造技术生成名人或网红的数字人形象进行直播，冒充其进行商品推荐或代言。③虚假互动：AI数字人配合自动化弹幕和虚假观众数据，营造虚假的直播热度和互动氛围。④未标注AI身份：使用AI数字人进行直播但未向观众明确标注其AI身份，违反相关法规要求。⑤情感欺诈：利用AI数字人在社交直播中与用户建立虚假的情感联系，诱导打赏或消费。",complexity:"中级",influence:"消费者被误导和欺诈、平台内容生态被破坏、品牌声誉受损、合规风险",avoidances:["A0064","A0066","A0006","A0006-001","A0020","A0048","A0043"],references:[{title:"关于加强网络直播规范管理工作的指导意见",link:"https://www.cac.gov.cn/"},{title:"AI数字人直播合规指引",link:"https://www.mct.gov.cn/"}],updated:"2026-06-11",keywords:["数字人直播欺诈","AI数字人直播","虚拟主播带货","无人直播诈骗","数字人带货","假直播"]},Ee={R0130:_e},Ve=e({R0131:()=>Ge,default:()=>je}),Ge={title:"二维码钓鱼风险",definition:"利用恶意二维码（QR Code）引导用户访问钓鱼网站、下载恶意软件或执行其他恶意操作的风险，也称为Quishing。",description:"二维码钓鱼风险（Quishing）是一种利用二维码作为攻击载体的新型钓鱼攻击方式。主要攻击场景包括：①替换支付码：在商户的收款二维码上覆盖恶意二维码，将用户的支付款项转移到攻击者账户。②钓鱼邮件嵌入：在钓鱼邮件中嵌入恶意二维码，绕过传统的URL检测和邮件安全网关。③公共场所投放：在公共场所张贴包含恶意链接的二维码，伪装为WiFi连接、优惠活动等。④伪造官方二维码：伪造政府机构、银行、快递公司等的官方二维码，诱导用户扫码后输入个人信息。⑤动态二维码攻击：利用短链接服务生成动态二维码，初始指向正常页面，后续修改为恶意页面以逃避检测。二维码钓鱼的特殊之处在于用户在扫码前无法直观判断二维码指向的内容，且移动设备上的安全防护通常弱于PC端。",complexity:"中级",influence:"用户个人信息泄露、财产损失、恶意软件感染、账号被盗",avoidances:["A0051","A0006","A0016","A0048","A0013","A0013-001"],references:[{title:"Quishing攻击趋势分析",link:"https://www.proofpoint.com/"},{title:"二维码安全风险防范指南",link:"https://www.cert.org.cn/"}],updated:"2026-06-11",keywords:["二维码钓鱼风险","二维码钓鱼","Quishing","恶意二维码","扫码钓鱼","扫码诈骗"]},je={R0131:Ge},ze=e({R0132:()=>Ue,default:()=>qe}),Ue={title:"SIM卡交换攻击",definition:"攻击者通过社会工程学手段欺骗电信运营商，将目标用户的手机号码转移到攻击者控制的SIM卡上，从而劫持基于手机号码的身份认证。",description:"SIM卡交换攻击（SIM Swap Attack）是一种针对基于手机号码的身份认证体系的攻击方式。攻击流程通常为：①信息收集：攻击者通过社交工程、数据泄露等渠道获取目标用户的个人信息（姓名、身份证号、手机号等）。②联系运营商：攻击者冒充目标用户联系电信运营商客服，以手机丢失、SIM卡损坏等理由申请补办SIM卡或号码转移。③号码劫持：运营商将目标号码转移到攻击者的SIM卡后，攻击者即可接收该号码的所有短信和电话。④账号接管：利用劫持的手机号码接收短信验证码，重置目标用户在各平台的密码，实现账号接管。⑤资产窃取：登录目标用户的银行、支付、加密货币等账户，转移资产。SIM Swap攻击的危害极大，因为大量在线服务依赖短信验证码作为身份认证手段。需要注意，该攻击在中国大陆的发生概率远低于海外，主要原因是中国运营商实行严格的实名制和补卡流程管控，但在海外（尤其是美国、欧洲）仍是高发威胁，对跨境业务和海外用户构成显著风险。",complexity:"高级",influence:"手机号码被劫持、所有基于短信验证的账号面临被接管风险、金融资产被盗",avoidances:["A0073","A0024","A0007","A0007-001","A0023","A0026","A0011"],references:[{title:"SIM Swap Fraud - FBI IC3",link:"https://www.ic3.gov/PSA/2022/PSA220208"},{title:"SIM Swap攻击防范 - CISA",link:"https://www.cisa.gov/news-events/cybersecurity-advisories"}],updated:"2026-06-11",keywords:["SIM卡交换攻击","SIM Swap","补卡劫持","换卡攻击","手机号劫持","SIM换卡诈骗"]},qe={R0132:Ue},He=e({R0133:()=>Qe,default:()=>Ke}),Qe={title:"隐私计算滥用风险",definition:"隐私计算技术（联邦学习、多方安全计算等）被滥用或实施不当，导致隐私保护目标未能实现甚至产生新的安全风险。",description:"隐私计算滥用风险是指在隐私计算技术的应用过程中，由于技术实施不当、恶意利用或监管缺失而产生的风险。主要包括：①联邦学习投毒：参与方在联邦学习过程中注入恶意模型更新，影响全局模型的准确性或植入后门。②梯度泄露攻击：通过分析联邦学习中共享的梯度信息，反推出参与方的原始训练数据。③隐私计算洗白：利用隐私计算技术为非法获取的数据'洗白'，使其看似经过了合规的隐私保护处理。④过度收集：以隐私计算为名义过度收集用户数据，实际上并未真正实施有效的隐私保护。⑤合规假象：部署了隐私计算系统但配置不当或实施不完整，造成合规的假象。⑥技术滥用：利用安全多方计算等技术协助非法活动（如联合洗钱、逃税等）。",complexity:"中级",influence:"隐私保护目标落空、用户数据实际上未得到有效保护、合规风险、技术信任度下降",avoidances:["A0069","A0054","A0052","A0043","A0072"],references:[{title:"隐私计算技术与应用白皮书 - 中国信通院",link:"http://www.caict.ac.cn/"},{title:"联邦学习安全与隐私综述",link:"https://arxiv.org/abs/2012.13995"}],updated:"2026-06-11",keywords:["隐私计算滥用风险","联邦学习滥用","多方安全计算风险","隐私计算安全","模型反推","联邦学习投毒"]},Ke={R0133:Qe},Xe=e({R0134:()=>Ye,default:()=>Je}),Ye={title:"大数据杀熟风险",definition:"平台利用大数据分析对老用户或特定用户群体实施差异化定价，对同一商品或服务向不同用户展示不同价格的风险。",description:"大数据杀熟风险是指互联网平台利用用户画像、消费习惯、设备信息、地理位置等大数据，对不同用户实施差异化定价策略，通常表现为对老用户、高消费用户或特定设备用户收取更高价格。主要表现形式包括：①价格歧视：同一商品或服务对不同用户展示不同价格，老用户价格高于新用户。②动态定价操纵：根据用户的浏览历史、搜索频率等行为数据动态调整价格，越频繁查看价格越高。③会员价格倒挂：付费会员看到的价格反而高于非会员用户。④设备差异定价：根据用户使用的设备品牌、型号等信息进行差异化定价。⑤地域差异定价：根据用户所在地区的消费水平进行不合理的差异化定价。这种行为违反了《个人信息保护法》《消费者权益保护法》等法律法规中关于公平交易和禁止价格歧视的规定。",complexity:"中级",influence:"消费者权益受损、平台面临监管处罚和罚款、用户信任度下降、品牌声誉受损",avoidances:["A0072","A0054","A0043","A0048","A0052"],references:[{title:"关于平台经济领域的反垄断指南",link:"https://scjgj.cq.gov.cn/zt_225/cjscjz/zcfg/gfxwj/202312/t20231215_12710745.html"},{title:"大数据杀熟的法律规制",link:"https://www.samr.gov.cn/"}],updated:"2026-06-11",keywords:["大数据杀熟风险","杀熟","差异化定价","价格歧视","老用户贵","千人千价"]},Je={R0134:Ye},Ze=e({R0135:()=>$e,default:()=>ei}),$e={title:"平台垄断滥用风险",definition:"互联网平台利用市场支配地位实施垄断行为，包括强制二选一、自我优待、封禁竞争对手等，面临反垄断监管处罚的风险。",description:"平台垄断滥用风险是指具有市场支配地位的互联网平台滥用其优势地位，实施限制竞争行为的风险。主要表现包括：①强制二选一：要求商家在多个平台之间做出排他性选择，不得在竞争对手平台经营。②自我优待：在搜索排名、流量分配等方面优先展示自营商品或服务，歧视第三方商家。③封禁竞争对手：屏蔽或限制竞争对手的链接、内容或服务在本平台的传播。④数据垄断：利用平台积累的海量数据建立竞争壁垒，拒绝向第三方开放必要的数据接口。⑤捆绑销售：利用平台优势地位强制用户使用其关联服务。⑥掠夺性定价：通过低于成本的定价策略排挤竞争对手。随着《反垄断法》修订和平台经济反垄断执法力度加大，平台面临的合规压力持续增加。",complexity:"中级",influence:"面临巨额反垄断罚款、业务整改要求、市场竞争秩序被破坏、中小商家权益受损",avoidances:["A0054","A0043","A0048","A0044","A0052"],references:[{title:"中华人民共和国反垄断法（2022修正）",link:"https://www.samr.gov.cn/"},{title:"关于平台经济领域的反垄断指南",link:"https://scjgj.cq.gov.cn/zt_225/cjscjz/zcfg/gfxwj/202312/t20231215_12710745.html"}],updated:"2026-06-11",keywords:["平台垄断滥用风险","二选一","自我优待","平台垄断","市场支配地位滥用","封禁竞对"]},ei={R0135:$e},ii=e({R0136:()=>ti,default:()=>ni}),ti={title:"合成身份欺诈",definition:"攻击者将真实个人信息片段与虚构信息拼凑组合，创造出全新的虚假身份，用于注册账号、申请信贷、骗取权益等欺诈活动。",description:"合成身份欺诈是一种区别于直接盗用身份（R0098）的高级身份欺诈手法。攻击者不直接使用某个真实个人的完整身份信息，而是将多个来源的真实信息片段（如真实的身份证号搭配虚假的姓名和地址）与虚构信息混合，创造出一个在系统中看似合法但实际不存在的身份。主要特征包括：①信息拼凑：将从数据泄露、社工库等渠道获取的真实信息碎片与虚构信息组合。②养号培育：利用合成身份注册账号后，通过正常交易行为逐步建立信用记录，提高账号可信度。③批量制造：利用自动化工具批量生成合成身份，形成规模化欺诈。④难以追溯：由于身份本身是虚构的，受害者难以被明确识别，欺诈行为发现周期长。⑤跨平台利用：同一合成身份可在多个平台注册使用，扩大欺诈收益。在国内场景中，常见于利用他人身份证号搭配虚假辅助信息注册电商、金融平台账号。",complexity:"高级",influence:"造成平台信贷损失、风控模型失效、合规风险增加，且由于受害者不明确导致损失难以追回",avoidances:["A0024","A0023","A0075","A0007","A0018","A0044"],references:[{title:"Synthetic Identity Fraud - Federal Reserve",link:"https://fedpaymentsimprovement.org/strategic-initiatives/payments-security/synthetic-identity-payments-fraud/"},{title:"合成身份欺诈检测技术研究",link:"https://www.bis.org/publ/work931.htm"}],updated:"2026-06-11",keywords:["合成身份欺诈","虚构身份骗贷","拼接身份","Synthetic Identity Fraud","身份拼凑","假身份养号"]},ni={R0136:ti},ai=e({R0137:()=>si,default:()=>oi}),si={title:"先买后付(BNPL)欺诈",definition:"利用先买后付（Buy Now Pay Later）信用额度进行欺诈消费后拒绝还款，或利用BNPL机制的审核漏洞骗取商品和资金。",description:"先买后付欺诈是针对BNPL信用消费模式的欺诈行为，在国内主要表现为花呗、白条等信用支付工具的滥用。主要欺诈模式包括：①虚假身份申请：利用合成身份或盗用他人身份开通BNPL额度后恶意消费。②套现欺诈：通过虚假交易将BNPL额度转化为现金，无意偿还。③多平台骗贷：同时在多个BNPL平台申请额度，集中消费后逃废债。④退款欺诈：利用BNPL的退款机制，在收到商品后发起退款但保留商品。⑤账号接管：盗取他人账号后利用其BNPL额度进行消费。⑥商户串通：与虚假商户合谋制造虚假交易套取BNPL资金。在国内电商场景中，花呗套现、白条套现已形成完整的灰产链条。",complexity:"中级",influence:"造成平台和金融机构的信贷损失、坏账率上升、影响BNPL业务的可持续发展",avoidances:["A0075","A0077","A0024","A0018","A0044","A0007"],references:[{title:"BNPL Fraud Trends - Juniper Research",link:"https://www.juniperresearch.com/research/fintech-payments/"},{title:"花呗白条套现风险防控",link:"https://www.pbccrc.org.cn/"}],updated:"2026-06-11",keywords:["先买后付(BNPL)欺诈","BNPL欺诈","先享后付骗单","花呗白条套现","分期骗货","免息分期欺诈"]},oi={R0137:si},ci=e({R0138:()=>ri,default:()=>li}),ri={title:"礼品卡/充值卡欺诈",definition:"利用盗刷的信用卡或其他非法资金购买礼品卡、充值卡进行洗钱变现，或通过伪造、篡改充值卡信息骗取平台资金。",description:"礼品卡/充值卡欺诈是一种利用预付卡类产品进行欺诈和洗钱的行为。主要模式包括：①盗卡购买：使用盗刷的信用卡批量购买电子礼品卡，再通过折价出售或直接消费完成洗钱。②伪造充值卡：伪造或篡改充值卡的卡号和密码信息，骗取平台充值金额。③礼品卡套利：利用不同渠道的价格差异批量购买礼品卡进行套利。④退款洗钱：用非法资金购买礼品卡后申请退款至不同账户，实现资金清洗。⑤社工诈骗变现：在电信诈骗中要求受害者购买礼品卡并提供卡号密码，快速转移资金。⑥内部盗取：内部员工利用系统漏洞生成或激活未授权的礼品卡。礼品卡因其匿名性强、流通性好、难以追踪的特点，成为网络犯罪中常用的资金转移工具。",complexity:"初级",influence:"造成平台直接经济损失、成为洗钱通道面临合规处罚、损害礼品卡业务信誉",avoidances:["A0077","A0075","A0044","A0018","A0007"],references:[{title:"礼品卡成“洗钱”新工具_无锡市梁溪区人民检察院",link:"https://wxlx.jsjc.gov.cn/tslm/yufang/202604/t20260421_1324439.shtml"},{title:"预付卡管理办法 - 中国人民银行",link:"http://www.pbc.gov.cn/"}],updated:"2026-06-11",keywords:["礼品卡/充值卡欺诈","礼品卡诈骗","充值卡洗钱","卡密盗刷","礼品卡套现","黑卡买卡"]},li={R0138:ri},di=e({R0139:()=>Ai,default:()=>pi}),Ai={title:"友好欺诈",definition:"消费者在正常收到商品或服务后，恶意向银行或支付机构发起拒付（Chargeback），谎称未收到商品或交易未经授权，以骗取退款同时保留商品。",description:"友好欺诈（Friendly Fraud / Chargeback Fraud）是一种由消费者发起的欺诈行为，区别于R0054恶意退货退款。其核心特征是消费者绕过商家直接通过银行或支付机构的争议解决机制发起拒付。主要表现形式包括：①虚假未收货声明：消费者收到商品后向银行声称未收到，发起拒付。②未授权交易声明：消费者自行完成交易后声称交易未经本人授权。③服务不满拒付：消费者在未与商家沟通的情况下直接发起拒付。④家庭成员消费：家庭成员（如子女）使用持卡人账户消费后，持卡人以未授权为由拒付。⑤买家后悔：消费者购买后后悔，通过拒付而非正常退货流程获取退款。⑥职业拒付人：有组织地利用拒付机制反复骗取退款的职业欺诈者。在国内场景中，类似行为表现为通过支付平台争议机制恶意申请退款。",complexity:"初级",influence:"商家承担商品损失和拒付手续费、拒付率过高导致支付通道被关闭、增加运营成本",avoidances:["A0077","A0074","A0075","A0044","A0024"],references:[{title:"Chargeback Fraud - Visa",link:"https://usa.visa.com/support/small-business/dispute-resolution.html"},{title:"【以案说险】 提高警惕 筑牢防线 携手防范和打击金融黑灰产",link:"https://mp.weixin.qq.com/s?__biz=MzA3NzAzNTY4MA==&mid=2651202715&idx=5&sn=d95acdfe6192cebdaf726a7143ba0ec1&chksm=85edf6ba99a1bdda669d92bdf957bdf01a8cecb98d95a4130ebe8876e728d7b9469edf694b3a&scene=27"}],updated:"2026-06-11",keywords:["友好欺诈","拒付欺诈","Chargeback Fraud","恶意拒付","拒付骗单","收到货后拒付"]},pi={R0139:Ai},ui=e({R0140:()=>fi,default:()=>wi}),fi={title:"会员/订阅滥用",definition:"利用会员试用期、订阅机制的漏洞反复获取免费权益，或通过共享、转售会员账号等方式非法获取和分发付费权益。",description:"会员/订阅滥用是针对平台会员体系和订阅服务的欺诈行为。主要模式包括：①试用期滥用：反复注册新账号获取免费试用期权益，到期后弃号重新注册。②权益共享：将个人会员账号的登录凭据分享给多人使用，超出授权使用范围。③会员转售：批量注册或盗取会员账号后在第三方平台低价转售。④退款保留权益：开通会员后使用权益，再通过退款机制取消订阅但保留已获取的权益（如已下载的内容）。⑤降级套利：利用会员等级变更的时间差，在高等级权益期间集中使用后立即降级。⑥家庭组滥用：将非家庭成员加入家庭共享计划，以低成本获取会员权益。在国内场景中，视频会员共享、音乐会员拼车等灰产活动普遍存在。",complexity:"初级",influence:"造成平台会员收入损失、付费用户体验下降、会员体系价值被稀释",avoidances:["A0074","A0076","A0007","A0077","A0044"],references:[{title:"Subscription Fraud Prevention - Recurly",link:"https://recurly.com/blog/recurly-stop-fraud-and-secure-growth/"}],updated:"2026-06-11",keywords:["会员/订阅滥用","试用薅羊毛","订阅欺诈","会员共享","合租会员","反复试用"]},wi={R0140:fi},ki=e({R0141:()=>yi,default:()=>hi}),yi={title:"地理位置欺诈",definition:"通过伪造GPS定位、使用VPN/代理等手段篡改地理位置信息，绕过地域限制获取区域性优惠、规避地域监管或实施位置相关的欺诈行为。",description:"地理位置欺诈是指攻击者通过技术手段伪造或篡改地理位置信息以获取不当利益的行为。主要表现形式包括：①区域优惠薅羊毛：伪造定位到特定区域以获取仅限该区域的优惠券、补贴或促销活动。②外卖/本地生活欺诈：伪造配送地址骗取新用户补贴，或伪造商家位置扩大服务范围。③打车/出行欺诈：司机伪造GPS轨迹虚增里程骗取车费，或伪造位置获取特定区域的高额订单。④签到/打卡作弊：伪造位置完成需要到店的签到任务获取积分或奖励。⑤监管规避：通过伪造位置规避特定地区的业务限制或合规要求。⑥竞价排名操控：伪造位置影响基于地理位置的搜索排名和广告投放。在国内场景中，外卖红包、打车补贴、区域限定活动等是位置欺诈的高发领域。",complexity:"初级",influence:"造成平台营销资源浪费、区域运营策略失效、基于位置的风控模型被绕过",avoidances:["A0076","A0074","A0010","A0077","A0044"],references:[{title:"GPS Spoofing Detection Techniques",link:"https://pmc.ncbi.nlm.nih.gov/articles/PMC11397858/"}],updated:"2026-06-11",keywords:["地理位置欺诈","定位作弊","GPS伪造","改定位","VPN改区","位置欺诈"]},hi={R0141:yi},mi=e({R0142:()=>gi,default:()=>Ii}),gi={title:"中间人攻击",definition:"攻击者在客户端与服务端之间拦截和篡改通信数据，窃取用户凭据、会话令牌或篡改交易内容，实现信息窃取或交易劫持。",description:"中间人攻击（Man-in-the-Middle Attack，MITM）是指攻击者秘密介入通信双方之间，拦截、查看甚至篡改传输数据的攻击方式。主要攻击场景包括：①WiFi劫持：在公共WiFi环境下拦截用户的网络通信，窃取登录凭据和敏感信息。②SSL/TLS降级攻击：通过SSL剥离等技术将加密连接降级为明文连接，使通信内容可被窃听。③ARP欺骗：在局域网内通过ARP欺骗将流量重定向到攻击者设备。④DNS劫持：篡改DNS解析结果将用户引导至恶意服务器。⑤证书伪造：使用伪造的SSL证书冒充合法服务器，拦截加密通信。⑥交易篡改：在支付过程中篡改收款账号、交易金额等关键信息。⑦会话劫持：窃取用户的会话令牌（Session Token/Cookie），冒充用户身份进行操作。在移动互联网场景中，恶意WiFi热点和APP中间人攻击是最常见的威胁。",complexity:"高级",influence:"用户凭据和敏感信息泄露、交易被篡改造成资金损失、用户对平台安全性失去信任",avoidances:["A0078","A0081","A0026","A0010","A0007"],references:[{title:"Man-in-the-Middle Attack - OWASP",link:"https://owasp.org/www-community/attacks/Manipulator-in-the-middle_attack"},{title:"MITM攻击防御指南 - CISA",link:"https://www.cisa.gov/news-events/cybersecurity-advisories"}],updated:"2026-06-11",keywords:["中间人攻击","MITM","会话劫持","流量劫持","SSL剥离","通信篡改"]},Ii={R0142:gi},Ri=e({R0143:()=>vi,default:()=>Si}),vi={title:"OAuth/SSO授权滥用",definition:"利用OAuth、SSO等第三方登录授权机制的实现漏洞或设计缺陷，获取用户账号控制权或越权访问用户数据。",description:"OAuth/SSO授权滥用是针对第三方登录和单点登录机制的攻击行为。主要攻击方式包括：①授权码劫持：通过开放重定向漏洞劫持OAuth授权码，获取用户的访问令牌。②CSRF绑定攻击：利用CSRF漏洞将攻击者的第三方账号绑定到受害者的平台账号上。③Token泄露利用：利用不安全的Token传输或存储方式窃取访问令牌和刷新令牌。④权限范围越权：在授权请求中扩大权限范围（Scope），获取超出必要的用户数据访问权限。⑤账号关联混淆：利用不同平台间账号关联逻辑的缺陷，实现账号接管。⑥隐式授权流滥用：利用隐式授权模式（Implicit Flow）中Token直接暴露在URL中的特点进行窃取。⑦第三方应用滥用：恶意第三方应用通过OAuth授权获取用户数据后进行滥用或出售。",complexity:"高级",influence:"用户账号被接管、个人数据泄露、平台间信任链被破坏、影响第三方登录生态安全",avoidances:["A0081","A0082","A0007","A0026","A0078","A0090"],references:[{title:"OAuth 2.0 Security Best Current Practice - IETF",link:"https://datatracker.ietf.org/doc/html/draft-ietf-oauth-security-topics"},{title:"OAuth安全攻防 - PortSwigger",link:"https://portswigger.net/web-security/oauth"}],updated:"2026-06-11",keywords:["OAuth/SSO授权滥用","OAuth滥用","SSO漏洞","授权码劫持","令牌劫持","第三方登录漏洞"]},Si={R0143:vi},Pi=e({R0144:()=>xi,default:()=>Ti}),xi={title:"域名/品牌仿冒",definition:"通过注册与目标品牌相似的域名、搭建仿冒网站或创建仿冒社交媒体账号，进行钓鱼攻击、流量劫持或品牌声誉损害。",description:"域名/品牌仿冒是指攻击者利用与知名品牌相似的域名、页面设计或品牌标识进行欺诈活动。主要表现形式包括：①相似域名注册（Typosquatting）：注册与目标品牌域名拼写相近的域名（如替换字母、增减字符），利用用户输入错误进行钓鱼。②同形异义字攻击（Homograph Attack）：使用Unicode中外观相似的字符注册域名，肉眼难以区分。③仿冒网站搭建：复制目标品牌的网站页面设计，搭建高仿钓鱼网站骗取用户凭据和支付信息。④仿冒APP发布：在非官方应用商店发布仿冒品牌的恶意APP。⑤社交媒体仿冒：创建仿冒品牌的社交媒体账号进行虚假营销或诈骗。⑥搜索引擎投毒：通过SEO手段使仿冒网站在搜索结果中排名靠前。⑦子域名接管：利用目标品牌已失效但DNS记录仍存在的子域名进行仿冒。",complexity:"初级",influence:"用户被钓鱼导致凭据和资金损失、品牌声誉受损、用户信任度下降、面临知识产权纠纷",avoidances:["A0078","A0082","A0044","A0010"],references:[{title:"Domain Name Abuse - ICANN",link:"https://www.icann.org/resources/pages/dndr-2012-02-25-en"},{title:"品牌保护与域名仿冒防范",link:"https://www.antiphishing.org/"}],updated:"2026-02-27",keywords:["域名/品牌仿冒","品牌仿冒","钓鱼域名","相似域名","山寨官网","域名抢注"]},Ti={R0144:xi},Ci=e({R0145:()=>bi,default:()=>Mi}),bi={title:"内容农场风险",definition:"通过批量生产低质量、高SEO优化的内容占据搜索排名，污染平台内容生态，误导用户并损害优质内容创作者的利益。",description:"内容农场风险是指利用自动化或低成本人力批量生产低质量内容以获取流量和收益的行为。主要表现形式包括：①SEO内容堆砌：批量生产针对热门关键词优化的低质量文章，占据搜索引擎排名。②AI生成内容泛滥：利用大语言模型批量生成看似专业但缺乏真实价值的内容。③内容搬运洗稿：将他人原创内容进行简单改写后大量发布，稀释原创内容的流量。④标题党和虚假信息：使用夸张标题和虚假信息吸引点击，传播错误信息。⑤评论区灌水：在商品评价、问答社区等场景批量发布虚假评论和回答。⑥多平台分发：将同一批低质内容在多个平台同步发布，最大化流量收益。⑦广告收益套利：通过低质内容获取大量页面浏览量，骗取广告分成收益。在国内场景中，内容农场严重影响了电商商品评价、知识问答、资讯平台等内容生态的质量。",complexity:"初级",influence:"平台内容质量下降、用户获取有效信息的成本增加、优质创作者流失、平台品牌价值受损",avoidances:["A0074","A0075","A0044","A0001"],references:[{title:"Content Farm Detection and Prevention",link:"https://developers.google.com/search/docs/essentials/spam-policies"},{title:"互联网信息内容生态治理规定",link:"http://www.cac.gov.cn/"}],updated:"2026-06-11",keywords:["内容农场风险","内容农场","SEO垃圾内容","洗稿站","批量伪原创","低质内容站"]},Mi={R0145:bi},Fi=e({R0146:()=>Di,default:()=>Li}),Di={title:"消费贷骗贷（真实补缴）",definition:"通过真实补缴社保、公积金等方式伪造还款能力，骗取消费贷款的欺诈行为。",description:"黑产团伙通过帮助借款人真实补缴社保、公积金等记录，伪造稳定收入和还款能力证明，从而骗取金融机构的消费贷款。这种手法相比传统的虚假材料更难识别，因为补缴记录是真实存在的。2026年这种手法成为主流，给金融机构风控带来新挑战。",complexity:"中级",influence:"高",avoidances:["A0024","A0075","A0077","A0018","A0044","A0051"],references:[{title:"2026年消费贷骗贷新变化:真实补缴成为主流手法",link:"https://www.163.com/dy/article/KOA4UHH60518STKV.html"}],updated:"2026-06-11",keywords:["消费贷骗贷（真实补缴）","真实补缴","补缴社保骗贷","补缴公积金骗贷","包装资质骗贷","消费贷骗贷"]},Li={R0146:Di},Oi=e({R0147:()=>Ni,default:()=>Bi}),Ni={title:"支付机构监管合规风险",definition:"支付机构因监管数据质量问题、穿透式监管要求不达标导致的合规风险。",description:"随着监管部门对支付机构实施穿透式监管和支付业务功能监管，支付机构需要提供高质量的监管数据，并对支付业务、外包合作、数据处理和风险控制链路保持可追溯。数据质量问题、校验规则不符、数据脱敏不当、供应商安全管理不到位、监管报送口径不一致等都可能导致合规风险和监管处罚。",complexity:"高级",influence:"高",avoidances:["A0054","A0050-002","A0080","A0070"],references:[{title:"非银行支付机构监督管理条例",link:"https://www.shanghaiinvest.com/cn/viewfile.php?id=19212"}],updated:"2026-06-13",keywords:["支付机构监管合规风险","支付牌照合规","备付金合规","反洗钱报送","穿透式监管","监管数据报送"]},Bi={R0147:Ni},Wi=e({R0148:()=>_i,default:()=>Ei}),_i={title:"AI智能体工具滥用/过度自主风险",definition:"集成外部工具、插件、MCP服务器或业务API的AI智能体，在恶意指令、错误目标或权限过大的情况下执行非预期业务操作的风险。",description:"AI智能体不再只是生成文本，而是可以调用搜索、浏览器、代码执行、数据库、工单、支付、营销、客服、办公自动化等工具完成真实操作。攻击者可通过直接或间接提示注入、恶意网页/文档、伪造工具描述、污染MCP上下文、诱导越权调用等方式，操纵智能体删除或泄露数据、发起交易、修改配置、发送消息、下载恶意内容或编排攻击链。该风险的关键特征是工具权限、外部数据和模型推理共同决定执行结果，传统输入过滤难以单独覆盖。",complexity:"高级",influence:"可导致敏感数据泄露、业务操作越权、自动化攻击放大、内部系统被间接操纵、审计追溯困难以及合规风险。",avoidances:["A0065","A0068","A0079","A0087","A0089"],references:[{title:"OWASP Top 10 for Agentic Applications",link:"https://genai.owasp.org/2025/12/09/owasp-top-10-for-agentic-applications-the-benchmark-for-agentic-security-in-the-age-of-autonomous-ai/"},{title:"Cybersecurity Forecast 2026 - Google Cloud",link:"https://cloud.google.com/security/resources/cybersecurity-forecast"}],updated:"2026-06-11",keywords:["AI智能体工具滥用/过度自主风险","Agentic AI风险","智能体越权调用","工具调用滥用","MCP滥用","自主代理失控"]},Ei={R0148:_i},Vi=e({R0149:()=>Gi,default:()=>ji}),Gi={title:"非人类身份与API密钥滥用风险",definition:"服务账号、API密钥、OAuth应用、CI/CD令牌、机器人账号、AI智能体凭证等非人类身份因暴露、权限过大、缺乏归属和缺少轮换而被滥用的风险。",description:"企业自动化、云原生、SaaS集成和AI智能体应用会产生大量非人类身份。这些身份通常以长期API密钥、访问令牌、证书、服务账号或应用授权形式存在，可能分散在代码仓库、配置文件、CI/CD变量、日志、工单、终端环境和第三方平台中。攻击者一旦获取这些凭证，就可能绕过人工登录流程，直接调用业务API、访问数据、修改配置、横向移动或维持持久化访问。该风险常与供应链攻击、信息窃取器、内部威胁和云权限配置不当相互叠加。",complexity:"中级",influence:"可导致批量数据泄露、业务API被滥用、云资源被接管、供应链污染、审计归因困难和长期潜伏访问。",avoidances:["A0019","A0050","A0068","A0079","A0080","A0087"],references:[{title:"Cybersecurity Forecast 2026 - Google Cloud",link:"https://cloud.google.com/security/resources/cybersecurity-forecast"},{title:"NIST SP 800-207: Zero Trust Architecture",link:"https://csrc.nist.gov/pubs/sp/800/207/final"}],updated:"2026-06-11",keywords:["非人类身份与API密钥滥用风险","NHI安全","服务账号滥用","API密钥泄露","机器身份安全","CI/CD令牌泄露"]},ji={R0149:Gi},zi=e({R0150:()=>Ui,default:()=>qi}),Ui={title:"杀猪盘/投资诈骗风险",definition:"犯罪团伙通过长期培养信任关系，诱导受害者在虚假投资平台（尤其加密货币平台）投入资金的系统性诈骗风险。",description:'杀猪盘是一种长期关系型投资诈骗，诈骗者通过社交媒体、交友软件等渠道接触潜在受害者，花费数周至数月建立信任关系后，引导受害者向其控制的虚假投资平台进行"投资"。这些投资平台实际上是伪造网站，受害者投入的资金在后台被迅速转移和洗钱。杀猪盘名称来源于"养猪"（培养信任）和"杀猪"（骗取资金）的犯罪流程。主要特征包括：①信任培养阶段：通过恋爱关系、友谊或专业建议获取受害者信任；②诱导投资阶段：展示虚假的高收益投资回报，引导受害者小额试水后加大投入；③收割阶段：当受害者试图提现时，要求支付高额手续费或税款，最终切断联系。杀猪盘已形成完整产业链，包括话术培训、虚假平台开发、资金洗白等环节，全球损失金额巨大。据FBI IC3报告，2024年仅美国投资诈骗损失即达93亿美元，其中加密货币相关诈骗占比超过一半。',complexity:"高级",influence:"可造成受害者巨额经济损失（单案可达数百万美元），引发平台信任危机，加剧监管压力，同时诈骗园区常涉及人口贩运和强迫劳动等严重社会问题。",avoidances:["A0024","A0075","A0018","A0029","A0077"],references:[{title:"FBI IC3 2024 Internet Crime Report",link:"https://www.ic3.gov/"},{title:"UNODC Southeast Asia Scam Operations Report",link:"https://www.unodc.org/"},{title:"Chainalysis 2026 Crypto Crime Report",link:"https://www.chainalysis.com/"}],updated:"2026-06-11",keywords:["杀猪盘/投资诈骗风险","杀猪盘","投资诈骗","虚假投资平台","恋爱投资诈骗","加密货币投资诈骗"]},qi={R0150:Ui},Hi=e({R0151:()=>Qi,default:()=>Ki}),Qi={title:"MFA绕过风险",definition:"攻击者通过技术手段绕过多因素认证（MFA）的安全保护，直接获取已通过认证的会话访问权限的风险。",description:"MFA绕过风险是指攻击者利用AiTM中间人攻击、MFA疲劳攻击、SIM卡交换、会话令牌窃取等手段，绕过多因素认证的安全验证，直接获取已认证会话的访问权限。MFA长期被视为账户安全的关键防线，但随着攻击技术的进化，MFA已不再是不可逾越的屏障。主要攻击路径包括：①AiTM攻击：通过反向代理拦截认证流程，窃取MFA验证后的会话Cookie；②MFA疲劳攻击（MFA Fatigue Attack）：向目标推送大量MFA验证请求，迫使用户因疲劳而误点确认；③SIM卡交换：通过社会工程使运营商将受害者手机号转移到攻击者控制的SIM卡，接收SMS验证码；④会话令牌窃取：通过信息窃取器窃取浏览器中存储的会话Cookie；⑤MFA凭据钓鱼：通过钓鱼页面同时收集密码和实时2FA令牌。据CrowdStrike 2026全球威胁报告，82%的网络攻击不使用恶意软件，而是通过窃取身份和会话令牌绕过MFA。",complexity:"高级",influence:"直接导致账户安全防线被突破，企业核心系统和数据可被未授权访问，传统MFA保护形同虚设。",avoidances:["A0007","A0073","A0026","A0078"],references:[{title:"CrowdStrike 2026 Global Threat Report",link:"https://www.crowdstrike.com/global-threat-report/"},{title:"CISA MFA Implementation Guidance",link:"https://www.cisa.gov/"}],updated:"2026-06-11",keywords:["MFA绕过风险","MFA绕过","2FA绕过","多因素认证绕过","AiTM","中间人钓鱼","MFA疲劳攻击","会话Cookie窃取","SIM卡交换"]},Ki={R0151:Qi},Xi=e({R0152:()=>Yi,default:()=>Ji}),Yi={title:"无恶意软件攻击风险",definition:"攻击者不使用传统恶意软件，而是利用窃取的身份凭据、合法工具和操作系统内置功能实施攻击的风险。",description:"无恶意软件攻击（Malware-Free Attack）是指攻击者完全不使用传统恶意软件（如木马、病毒、勒索软件等），而是通过窃取合法身份凭据、利用系统内置工具和合法云服务实施攻击的方式。这种攻击方式使传统的基于恶意软件检测的安全防护体系效果极差。主要攻击手法包括：①凭据窃取与滥用：通过钓鱼、AiTM攻击、信息窃取器等手段窃取合法账户凭据和会话令牌，直接以合法身份登录系统；②Living-off-the-Land（LotL）：利用操作系统内置工具（如PowerShell、WMI、PsExec等）执行攻击操作，不留下恶意文件痕迹；③合法云服务滥用：使用合法的云存储、协作工具和远程管理软件进行数据渗出和远程控制；④身份冒充：利用窃取的管理员凭据直接操控Active Directory、云管理控制台等关键基础设施；⑤供应链合法权限滥用：利用合法的第三方供应商访问权限进行横向移动。据Microsoft和CrowdStrike报告，2025年约82%的网络攻击不使用恶意软件。",complexity:"高级",influence:"传统安全检测体系几乎失效，攻击者以合法身份在系统内长期潜伏，难以被发现和阻断，数据泄露和业务破坏风险极高。",avoidances:["A0075","A0078","A0068","A0079"],references:[{title:"Microsoft Digital Defense Report 2025",link:"https://www.microsoft.com/en-us/security/business/microsoft-digital-defense-report"},{title:"CrowdStrike 2026 Global Threat Report",link:"https://www.crowdstrike.com/global-threat-report/"}],updated:"2026-06-11",keywords:["无恶意软件攻击风险","无恶意软件攻击","Malware-Free Attack","无文件攻击","LOTL攻击","Living off the Land","系统自带工具滥用","合法工具滥用","凭据攻击"]},Ji={R0152:Yi},Zi=e({R0153:()=>$i,default:()=>et}),$i={title:"影子AI风险",definition:"企业员工未经授权使用第三方AI工具处理业务数据，导致数据泄露、合规违规和知识产权外泄的风险。",description:"影子AI风险是指员工在未经组织正式批准和安全评估的情况下，将敏感业务数据输入第三方AI服务或使用未经审核的AI工具处理业务数据的行为带来的风险。区别于R0071生成式AI风险关注AI系统自身的技术风险，影子AI风险关注的是员工违规使用AI工具的组织管理风险。主要风险场景包括：①敏感数据输入：将客户数据、财务报表、源代码等敏感信息输入公开AI服务，可能导致数据被用于模型训练或泄露给第三方；②合规违规：使用未通过安全评估的AI工具处理受监管数据（如个人隐私数据、医疗数据），违反数据保护法规；③知识产权外泄：将商业秘密、专利技术等通过AI工具处理，可能导致知识产权泄露；④决策依赖：过度依赖AI生成的未经验证的分析和建议，可能导致业务决策失误；⑤数据残留：输入AI服务的数据可能被服务商缓存或存储，无法彻底删除。随着ChatGPT等工具的普及，78%的企业存在影子AI使用行为。",complexity:"中级",influence:"可导致敏感数据泄露、合规违规处罚、商业秘密外泄、客户信任丧失，以及知识产权不可逆损失。",avoidances:["A0035","A0068","A0080","A0083","A0094"],references:[{title:"Cisco 2025 Data Privacy Benchmark Study",link:"https://www.cisco.com/c/en/us/about/trust-center/data-privacy-benchmark-study.html"},{title:"NIST AI 100-1: AI Risk Management Framework",link:"https://www.nist.gov/itl/ai-risk-management-framework"},{title:"What Is Shadow AI? - IBM",link:"https://www.ibm.com/think/topics/shadow-ai"}],updated:"2026-06-11",keywords:["影子AI风险","影子AI","Shadow AI","未授权AI工具","员工私用AI","私接AI","敏感数据喂给AI","第三方大模型滥用"]},et={R0153:$i},it=e({R0154:()=>tt,default:()=>nt}),tt={title:"ClickFix欺骗风险",definition:"攻击者伪装成系统修复提示或验证码验证步骤，诱骗用户主动执行恶意代码的社会工程风险。",description:'ClickFix欺骗风险是一种新型社会工程攻击风险，攻击者利用用户对系统错误提示和修复操作的信任心理，将恶意代码执行伪装成合法的系统操作。区别于R0084钓鱼攻击侧重于信息窃取，ClickFix欺骗风险侧重于诱骗用户直接在本地执行恶意代码。主要风险场景包括：①终端被控制：用户执行恶意命令后，攻击者获得终端的远程控制权；②凭据窃取：恶意命令在后台窃取浏览器中存储的密码、Cookie和会话令牌；③勒索软件部署：通过恶意命令下载并执行勒索软件，加密用户文件；④持久化后门：在系统中植入持久化后门，实现长期潜伏访问；⑤横向移动：以被控终端为跳板，向企业内网其他系统发起攻击。ClickFix攻击的社会工程效果显著，因为用户往往认为自己在"修复"问题而非"被攻击"。',complexity:"中级",influence:"可导致终端被完全控制、凭据批量泄露、勒索软件感染和企业内网被渗透。",avoidances:["A0051","A0078","A0001"],references:[{title:"Security Brief: ClickFix Social Engineering Technique Floods Threat Landscape",link:"https://www.proofpoint.com/us/blog/threat-insight/security-brief-clickfix-social-engineering-technique-floods-threat-landscape"},{title:"ClickFix Attacks - HHS Sector Alert",link:"https://www.hhs.gov/sites/default/files/clickfix-attacks-sector-alert-tlpclear.pdf"},{title:"Caught in the CAPTCHA: How ClickFix is Weaponizing Verification Fatigue",link:"https://www.sentinelone.com/blog/how-clickfix-is-weaponizing-verification-fatigue-to-deliver-rats-infostealers/"}],updated:"2026-06-11",keywords:["ClickFix欺骗风险","ClickFix","假修复攻击","伪装系统报错","复制粘贴命令攻击","PowerShell诱导执行","假验证提示","社工修复指引"]},nt={R0154:tt},at=e({R0155:()=>st,default:()=>ot}),st={title:"跨境数据走私风险",definition:"利用各种隐蔽渠道将敏感数据非法转移出境，规避数据出境安全监管的风险。",description:"跨境数据走私风险是指通过隐蔽手段将受监管的敏感数据非法转移出境的风险。区别于R0077数据出境合规风险关注的是合规层面的违规，跨境数据走私风险关注的是主动的、有目的的数据窃取和转移行为。主要手法包括：①隐蔽通道传输：通过加密隧道、代理服务器、CDN等隐蔽通道将数据传输至境外服务器；②数据碎片化：将数据拆分成小片段，通过多个渠道分散传输，降低被检测的概率；③物理介质走私：将数据存储在便携设备中，由人员携带出境；④云服务滥用：利用境外云存储和SaaS服务作为数据中转站；⑤API滥用：通过合法API接口进行高频数据导出，规避数据出境审批；⑥供应链渠道：通过第三方供应商的境外系统间接传输数据。跨境数据走私对企业数据主权和国家安全构成严重威胁。",complexity:"高级",influence:"可导致核心数据资产外泄、国家安全风险、合规重罚，以及竞争优势丧失。",avoidances:["A0080","A0035","A0068","A0067"],references:[{title:"China Data Security Law and Cross-Border Data Transfer Regulations",link:"https://www.dataguidance.com/notes/china-data-security-law"},{title:"MITRE: Data Exfiltration Techniques",link:"https://attack.mitre.org/tactics/TA0010/"},{title:"PwC: Global Data Transfer Compliance Report",link:"https://www.pwc.com/us/en/services/consulting/cybersecurity-data-tech-risk/data-risk-privacy.html"}],updated:"2026-06-11",keywords:["跨境数据走私风险","数据走私","隐蔽数据出境","数据偷运出境","跨境数据偷渡","境外数据外传","数据渗出出境","隐蔽外发"]},ot={R0155:st},ct=e({R0156:()=>rt,default:()=>lt}),rt={title:"抗量子加密风险",definition:"量子计算的发展可能在未来破解当前广泛使用的RSA、ECC等经典加密算法，导致加密通信和数据保护失效的风险。",description:'抗量子加密风险是指量子计算技术的发展可能在未来使当前广泛使用的RSA、ECC等经典公钥加密算法不再安全，从而导致加密通信、数字签名和数据保护失效的风险。主要威胁场景包括：①"先收集后解密"（Harvest Now, Decrypt Later）：攻击者现在窃取加密数据，等待量子计算机成熟后解密，对长期保密数据构成即时威胁；②数字签名伪造：量子计算机可能破解RSA和ECC签名算法，使攻击者能够伪造合法的数字证书和签名；③加密通信破解：TLS/SSL等基于经典加密的通信协议可能被破解，导致通信内容暴露；④区块链安全威胁：加密货币和智能合约使用的椭圆曲线签名可能被破解。虽然通用量子计算机尚未实现，但各国政府和安全机构已将抗量子加密迁移列为优先事项，NIST于2024年发布了首批后量子密码标准。',complexity:"高级",influence:"可导致长期保密数据泄露、数字信任体系崩溃、加密货币安全失效，以及通信隐私全面丧失。",avoidances:["A0091","A0022"],references:[{title:"NIST Post-Quantum Cryptography Standards",link:"https://csrc.nist.gov/projects/post-quantum-cryptography"},{title:"ENISA: Post-Quantum Cryptography Integration Study",link:"https://www.enisa.europa.eu/publications/post-quantum-cryptography-integration-study"},{title:"NSA: Quantum Computing and Post-Quantum Cryptography",link:"https://www.nsa.gov/Cybersecurity/Post-Quantum-Cryptography/"}],updated:"2026-06-11",keywords:["抗量子加密风险","后量子密码","PQC","抗量子密码","量子计算破密","RSA失效","ECC失效","量子安全迁移"]},lt={R0156:rt},dt=e({R0157:()=>At,default:()=>pt}),At={title:"AI浏览器/手机黑箱风险",definition:"AI原生浏览器和手机中嵌入的AI功能缺乏透明度和可解释性，导致用户无法理解和控制AI决策行为的风险。",description:"AI浏览器/手机黑箱风险是指新一代AI原生设备（如AI PC、AI手机、AI浏览器）中嵌入的AI功能在决策过程中缺乏透明度和可解释性，使用户无法理解和控制AI的行为。区别于R0148 AI智能体工具滥用关注的是AI被恶意利用，AI黑箱风险关注的是AI系统本身的不透明性和不可控性。主要风险场景包括：①自主决策不可解释：AI助手自动执行操作（如自动回复邮件、自动购物、自动订阅服务）但无法向用户解释决策依据；②数据收集不透明：AI功能在后台持续收集用户行为数据，用户无法知悉数据收集的范围和用途；③偏见与歧视：AI决策可能包含训练数据中的偏见，导致不公平的推荐、筛选或定价；④错误决策不可纠正：AI的错误决策可能被用户误信为正确，且缺乏有效的纠正机制；⑤隐私泄露通道：AI功能的云端处理可能成为数据泄露的新通道。随着AI PC和AI手机的市场普及，该风险的影响面正在迅速扩大。",complexity:"中级",influence:"可导致用户自主权丧失、隐私持续泄露、不公平待遇、错误决策扩散，以及社会信任体系弱化。",avoidances:["A0072","A0089","A0083"],references:[{title:"EU AI Act: Transparency Requirements for AI Systems",link:"https://artificialintelligenceact.eu/"},{title:"NIST AI 100-4: AI Transparency and Explainability",link:"https://www.nist.gov/artificial-intelligence"},{title:"Mozilla: AI Black Box and Consumer Privacy",link:"https://foundation.mozilla.org/en/privacynotincluded/"}],updated:"2026-06-11",keywords:["AI浏览器/手机黑箱风险","AI黑箱","AI浏览器黑箱","AI手机黑箱","AI原生设备","端侧AI黑箱","不可解释性","AI代操作失控"]},pt={R0157:At},ut=e({R0158:()=>ft,default:()=>wt}),ft={title:"算力盗用风险",definition:"攻击者非法获取和占用他人计算资源（GPU、CPU、云算力等）用于加密货币挖矿或AI模型训练的风险。",description:"算力盗用风险是指攻击者通过入侵服务器、滥用云服务账号或劫持AI训练任务等方式，非法获取和占用他人计算资源的风险。区别于R0086服务器挖矿是挖矿行为本身的风险，算力盗用风险侧重于计算资源被非法占用的资源窃取层面。主要攻击手法包括：①云算力盗用：入侵云服务账号，创建大量GPU实例用于挖矿或AI训练；②服务器入侵：入侵企业服务器，利用其计算资源进行挖矿或模型训练；③AI训练劫持：在分布式AI训练过程中注入恶意任务，占用训练集群的算力；④容器逃逸：从容器中逃逸到宿主机，利用宿主机算力；⑤供应链算力滥用：在开源AI工具或模型中植入后门，将受害者算力导向攻击者的任务。随着AI大模型训练对GPU算力需求的爆发式增长，算力已成为新的高价值窃取目标。",complexity:"中级",influence:"可导致计算资源被大量占用、云服务费用暴增、业务性能下降，以及AI训练数据和模型被窃取。",avoidances:["A0078","A0079","A0068"],references:[{title:"MITRE ATT&CK: Resource Hijacking (T1496)",link:"https://attack.mitre.org/techniques/T1496/"},{title:"CrowdStrike: Cloud Compute Resource Abuse Report",link:"https://www.crowdstrike.com/resources/reports/"},{title:"【黑产大数据】2025年互联网黑灰产趋势年度总结|洗钱|欺诈|大陆|...",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-11",keywords:["算力盗用风险","资源劫持","算力滥用","云资源盗刷","GPU盗用","CPU盗用","AI算力盗刷","云账号盗刷"]},wt={R0158:ft},kt=e({R0159:()=>yt,default:()=>ht}),yt={title:"智能合约漏洞",definition:"区块链智能合约代码中存在的安全缺陷，可被攻击者利用窃取资产或破坏合约逻辑。",description:"智能合约一旦部署到区块链上通常无法修改，代码中的漏洞（如重入攻击、整数溢出、权限控制缺陷等）可能导致严重的资金损失。攻击者可通过精心构造的交易触发漏洞，转移合约中的数字资产或操纵合约状态。",complexity:"高级",influence:"造成平台或用户的数字资产损失，破坏智能合约业务逻辑，影响区块链应用信誉。",avoidances:["A0095","A0096","A0097"],references:[{title:"OWASP Smart Contract Top 10",link:"https://owasp.org/www-project-smart-contract-top-10/"},{title:"The DAO Attack Analysis",link:"https://www.gemini.com/cryptopedia/the-dao-hack-makerdao"}],updated:"2026-06-15",keywords:["智能合约漏洞","合约安全","重入攻击","整数溢出","权限漏洞","区块链安全","reentrancy","smart contract vulnerability"]},ht={R0159:yt},mt=e({R0160:()=>gt,default:()=>It}),gt={title:"闪电贷攻击",definition:"利用DeFi协议中的闪电贷功能，在单笔交易内借入大量资产进行价格操纵或套利攻击。",description:"闪电贷允许用户在无抵押的情况下借入大量加密资产，但必须在同一交易内归还。攻击者利用这一特性，通过操纵预言机价格、利用协议间价差、触发清算机制等方式获利，给DeFi协议造成巨额损失。",complexity:"高级",influence:"导致DeFi协议资金池被掏空，用户资产损失，破坏市场价格机制。",avoidances:["A0098","A0099","A0100"],references:[{title:"Flash Loan Attack Explained",link:"https://consensys.io/blog/what-is-a-flash-loan-attack"}],updated:"2026-06-15",keywords:["闪电贷攻击","DeFi攻击","价格操纵","预言机攻击","无抵押借贷","flash loan attack"]},It={R0160:gt},Rt=e({R0161:()=>vt,default:()=>St}),vt={title:"跨链桥攻击",definition:"针对区块链跨链桥协议的攻击，通过利用桥接合约漏洞或验证机制缺陷窃取锁定资产。",description:"跨链桥用于在不同区块链之间转移资产，通常需要在源链锁定资产并在目标链铸造等值代币。攻击者可利用桥接合约的漏洞、多签验证缺陷、预言机操纵等方式，在未锁定资产的情况下铸造代币，或直接窃取锁定池中的资产。",complexity:"高级",influence:"造成跨链桥资金池被盗，用户跨链资产损失，影响多链生态互操作性。",avoidances:["A0101","A0102","A0103"],references:[{title:"Cross-Chain Bridge Security",link:"https://blog.chainalysis.com/reports/cross-chain-bridge-hacks-2022/"}],updated:"2026-06-15",keywords:["跨链桥攻击","桥接协议","跨链安全","多链攻击","资产桥接","cross-chain bridge attack"]},St={R0161:vt},Pt=e({R0162:()=>xt,default:()=>Tt}),xt={title:"私钥泄露与管理风险",definition:"区块链钱包私钥被窃取、泄露或管理不当，导致数字资产被盗。",description:"私钥是控制区块链资产的唯一凭证，一旦泄露无法撤销。攻击者可通过钓鱼、恶意软件、社会工程、不安全存储等方式获取私钥。此外，助记词泄露、多签门槛设置不当、密钥生成随机性不足等也会造成资产风险。",complexity:"中级",influence:"用户数字资产被盗且无法追回，平台托管资产面临安全威胁。",avoidances:["A0104","A0105","A0106"],references:[{title:"Cryptocurrency Wallet Security Best Practices",link:"https://www.cisa.gov/sites/default/files/publications/data_backup_options.pdf"}],updated:"2026-06-15",keywords:["私钥泄露与管理风险","私钥泄露","钱包安全","助记词","密钥管理","冷钱包","热钱包","private key leak"]},Tt={R0162:xt},Ct=e({R0163:()=>bt,default:()=>Mt}),bt={title:"智能设备劫持",definition:"攻击者通过漏洞控制物联网智能设备，用于窃取数据、监控用户或发起攻击。",description:"物联网设备常因固件漏洞、弱密码、缺少安全更新等问题被攻击者远程控制。被劫持的设备可用于窃听、偷拍、数据窃取，或被纳入僵尸网络发起DDoS攻击，还可能成为入侵内网的跳板。",complexity:"高级",influence:"用户隐私泄露，设备成为攻击工具，企业内网被渗透。",avoidances:["A0107","A0108","A0109"],references:[{title:"OWASP IoT Top 10",link:"https://owasp.org/www-project-internet-of-things/"}],updated:"2026-06-15",keywords:["智能设备劫持","物联网劫持","IoT安全","设备控制","智能家居安全","IoT hijacking"]},Mt={R0163:bt},Ft=e({R0164:()=>Dt,default:()=>Lt}),Dt={title:"固件篡改与后门",definition:"物联网设备固件被植入恶意代码或后门，导致设备功能被操控或数据被窃取。",description:"攻击者通过供应链投毒、OTA更新劫持、物理接触等方式篡改设备固件，植入后门程序。被篡改的固件可长期潜伏，持续窃取数据、监控用户行为，或在特定时机触发恶意行为，且难以被常规安全软件检测。",complexity:"高级",influence:"设备长期被监控，数据持续泄露，成为高级持续威胁（APT）的入口。",avoidances:["A0110","A0111","A0112"],references:[{title:"IoT Firmware Security Best Practices",link:"https://www.nist.gov/publications/recommendations-iot-device-manufacturers"}],updated:"2026-06-15",keywords:["固件篡改与后门","固件篡改","固件后门","IoT后门","固件安全","OTA劫持","firmware tampering"]},Lt={R0164:Dt},Ot=e({R0165:()=>Nt,default:()=>Bt}),Nt={title:"IoT僵尸网络",definition:"大量被攻陷的物联网设备被组织成僵尸网络，用于发起分布式攻击或其他恶意活动。",description:"攻击者利用物联网设备的安全漏洞（如默认密码、未修补漏洞）批量控制设备，形成僵尸网络（如Mirai、Mozi等）。这些僵尸网络可发起大规模DDoS攻击、进行加密货币挖矿、发送垃圾邮件或作为攻击跳板。",complexity:"高级",influence:"设备性能下降或瘫痪，成为攻击基础设施的一部分，影响互联网稳定性。",avoidances:["A0113","A0114","A0115"],references:[{title:"Mirai Botnet Analysis",link:"https://www.cloudflare.com/learning/ddos/glossary/mirai-botnet/"}],updated:"2026-06-15",keywords:["IoT僵尸网络","物联网僵尸网络","Mirai","设备僵尸网络","IoT DDoS","IoT botnet"]},Bt={R0165:Nt},Wt=e({R0166:()=>_t,default:()=>Et}),_t={title:"IoT设备默认凭据风险",definition:"物联网设备使用出厂默认用户名密码未修改，导致被批量攻破。",description:"大量IoT设备出厂时使用相同的默认凭据（如admin/admin），用户部署后未修改或无法修改。攻击者利用公开的默认凭据列表进行批量扫描和登录，轻松控制大量设备。部分设备甚至存在硬编码凭据或隐藏后门账号。",complexity:"初级",influence:"设备被批量控制，用户数据泄露，设备被纳入僵尸网络。",avoidances:["A0116","A0117","A0118"],references:[{title:"Default Password Lists",link:"https://github.com/danielmiessler/SecLists/tree/master/Passwords/Default-Credentials"}],updated:"2026-06-15",keywords:["IoT设备默认凭据风险","默认凭据","默认密码","弱口令","硬编码密码","IoT弱密码","default credentials"]},Et={R0166:_t},Vt=e({R0167:()=>Gt,default:()=>jt}),Gt={title:"DAO治理攻击",definition:"攻击者通过操纵治理代币或投票机制，控制去中心化自治组织（DAO）的决策权。",description:"DAO 通过代币投票进行治理决策。攻击者可通过大量购买或借贷治理代币、利用闪电贷临时获得投票权、贿赂代币持有者、利用提案机制漏洞等方式，操纵投票结果通过恶意提案，如转移资金、修改合约参数、授予自己特权等。",complexity:"高级",influence:"DAO 资金被盗或滥用，治理机制失效，社区信任崩塌。",avoidances:["A0119","A0120","A0121"],references:[{title:"DAO Governance Attack Vectors",link:"https://blog.openzeppelin.com/secure-smart-contract-guidelines-the-dangers-of-price-oracles"}],updated:"2026-06-15",keywords:["DAO治理攻击","治理代币操纵","投票攻击","提案恶意","闪电贷投票","governance attack"]},jt={R0167:Gt},zt=e({R0168:()=>Ut,default:()=>qt}),Ut={title:"Rug Pull（项目方跑路）",definition:"Web3 项目方在募集资金或吸引流动性后突然撤资消失，投资者资金归零。",description:"Rug Pull 是加密货币领域常见的欺诈手段。项目方通过虚假宣传吸引用户投资或提供流动性，然后通过移除流动性池、转移合约所有权、利用后门功能等方式卷走资金。部分项目表面合法但预埋代码漏洞，在合适时机收割用户。",complexity:"中级",influence:"投资者资金全部损失，破坏 Web3 生态信任，引发监管关注。",avoidances:["A0122","A0123","A0124"],references:[{title:"How to Spot a Rug Pull",link:"https://www.coindesk.com/learn/what-is-a-rug-pull-in-crypto/"}],updated:"2026-06-15",keywords:["Rug Pull（项目方跑路）","Rug Pull","项目方跑路","卷款跑路","撤资退出骗局","流动性撤出","exit scam"]},qt={R0168:Ut},Ht=e({R0169:()=>Qt,default:()=>Kt}),Qt={title:"预言机操纵",definition:"攻击者操纵区块链预言机提供的外部数据，影响依赖该数据的智能合约和 DeFi 协议。",description:"预言机为智能合约提供链外数据（如价格、天气等）。攻击者可通过操纵数据源、攻击预言机节点、利用价格延迟、在低流动性市场制造虚假价格等方式，使预言机报告错误数据，导致 DeFi 协议错误清算、价格错误计算等，从中获利。",complexity:"高级",influence:"DeFi 协议资金损失，用户被错误清算，市场价格机制失效。",avoidances:["A0125","A0126","A0127"],references:[{title:"Oracle Manipulation Attacks",link:"https://blog.chain.link/what-is-oracle-manipulation/"}],updated:"2026-06-15",keywords:["预言机操纵","价格操纵","数据源攻击","预言机攻击","价格预言机","oracle manipulation"]},Kt={R0169:Qt},Xt=e({R0170:()=>Yt,default:()=>Jt}),Yt={title:"MEV攻击（矿工可提取价值）",definition:"矿工或验证者通过重新排序、插入或审查交易来提取额外价值，损害普通用户利益。",description:"MEV（Miner/Maximal Extractable Value）是指矿工/验证者通过控制区块内交易顺序获取的额外利益。常见手法包括：抢先交易（Front-running）、夹击交易（Sandwich Attack）、套利交易重排等。用户的交易被恶意重排后，可能遭受滑点损失、交易失败或被迫以不利价格成交。",complexity:"高级",influence:"用户交易成本增加，遭受价格滑点损失，区块链公平性受损。",avoidances:["A0128","A0129","A0130"],references:[{title:"Flashbots MEV Research",link:"https://docs.flashbots.net/"}],updated:"2026-06-15",keywords:["MEV攻击（矿工可提取价值）","MEV攻击","矿工可提取价值","抢先交易","夹击攻击","交易重排","front-running","sandwich attack"]},Jt={R0170:Yt},Zt=e({R0171:()=>$t,default:()=>en}),$t={title:"51%攻击（双花攻击）",definition:"攻击者控制区块链网络超过51%的算力或权益，从而操纵区块链共识机制实施双花等攻击。",description:"当攻击者掌握区块链网络过半的计算能力（PoW）或质押代币（PoS）时，可以重组区块链历史、逆转已确认交易、实施双花攻击（同一资产多次支付）、审查特定交易等。对于算力较小的区块链网络，此类攻击成本较低且更易实施。",complexity:"高级",influence:"交易无法信任，资产被双花盗取，区块链共识机制崩溃，网络价值归零。",avoidances:["A0131","A0132","A0133"],references:[{title:"51% Attack Explained",link:"https://www.investopedia.com/terms/1/51-attack.asp"}],updated:"2026-06-15",keywords:["51%攻击（双花攻击）","51%攻击","双花攻击","算力攻击","共识攻击","区块重组","majority attack","double-spend"]},en={R0171:$t},tn=e({R0172:()=>nn,default:()=>an}),nn={title:"女巫攻击（Sybil Attack）",definition:"攻击者创建大量虚假身份节点，试图控制或破坏去中心化网络的运作。",description:"女巫攻击指在P2P网络中，攻击者通过控制多个伪造节点身份来获得不成比例的影响力。可用于：操纵投票和共识、包围并孤立目标节点、发起日食攻击、污染路由表、破坏声誉系统等。区块链、社交网络、物联网等去中心化系统都面临此威胁。",complexity:"高级",influence:"网络共识被操纵，节点通信被隔离，去中心化特性失效，系统安全性降级。",avoidances:[],references:[{title:"Sybil Attack on Blockchain",link:"https://en.wikipedia.org/wiki/Sybil_attack"}],updated:"2026-06-15",keywords:["女巫攻击（Sybil Attack）","女巫攻击","虚假节点","身份伪造","节点欺骗","P2P攻击","Sybil attack"]},an={R0172:nn},sn=e({R0173:()=>on,default:()=>cn}),on={title:"Gas费操纵",definition:"攻击者通过操纵区块链交易Gas费用，影响交易顺序或造成网络拥堵。",description:"Gas费决定了交易在区块中的优先级。攻击者可通过：设置极高Gas费抢先执行交易（Front-running）、发送大量低Gas交易堵塞网络、利用Gas价格波动进行套利、操纵Gas拍卖机制等方式，使普通用户交易延迟或失败，或强迫用户支付更高手续费。",complexity:"高级",influence:"用户交易成本飙升，网络拥堵瘫痪，交易顺序被恶意操纵。",avoidances:[],references:[{title:"Ethereum Gas Fee Manipulation",link:"https://ethereum.org/en/developers/docs/gas/"}],updated:"2026-06-15",keywords:["Gas费操纵","交易费攻击","网络拥堵攻击","Gas拍卖","优先级操纵","gas manipulation"]},cn={R0173:on},rn=e({R0174:()=>ln,default:()=>dn}),ln={title:"链上隐私泄露",definition:"区块链交易的公开透明特性导致用户身份、资产、交易行为等隐私信息被追踪分析。",description:"公链上所有交易记录永久公开可查，攻击者可通过链上数据分析、地址聚类、交易图谱分析等技术手段，关联用户真实身份与钱包地址，追踪资产流向和交易习惯。即使使用假名地址，也可能通过交易模式、金额特征、时间关联等被去匿名化。",complexity:"高级",influence:"用户资产和交易隐私完全暴露，成为针对性攻击目标，引发安全和监管风险。",avoidances:["A0134","A0135","A0136"],references:[{title:"Blockchain Privacy Issues",link:"https://www.sciencedirect.com/science/article/pii/S1574013720304391"}],updated:"2026-06-15",keywords:["链上隐私泄露","地址追踪","交易分析","去匿名化","区块链隐私","on-chain privacy leak"]},dn={R0174:ln},An=e({R0175:()=>pn,default:()=>un}),pn={title:"区块链重放攻击",definition:"攻击者将一条链上的合法交易在另一条链或同一链上重复执行，导致资产被重复转移。",description:"区块链分叉或跨链场景下，如果交易签名未包含链ID等防重放标识，攻击者可将用户在一条链上的签名交易复制到另一条链上执行。典型场景包括硬分叉后的两条链、跨链转账、合约升级等。用户可能在不知情的情况下在多条链上损失资产。",complexity:"高级",influence:"用户资产在多条链上被重复转移，造成额外损失。",avoidances:["A0137","A0138","A0139"],references:[{title:"Replay Attack Protection",link:"https://eips.ethereum.org/EIPS/eip-155"}],updated:"2026-06-15",keywords:["区块链重放攻击","重放攻击","交易重放","跨链重放","分叉攻击","签名复用","replay attack"]},un={R0175:pn},fn=e({R0176:()=>wn,default:()=>kn}),wn={title:"时间戳依赖攻击",definition:"智能合约依赖区块时间戳进行逻辑判断，矿工可操纵时间戳影响合约执行结果。",description:"智能合约常使用区块时间戳（block.timestamp）来实现时间相关逻辑，如抽奖开奖、期权到期、利息计算等。矿工在一定范围内（通常15秒）可自由设置区块时间戳，攻击者可利用此特性操纵合约结果，如选择有利的开奖时间、提前触发或延迟执行等。",complexity:"高级",influence:"合约逻辑被操纵，抽奖结果可预测，时间敏感业务失效。",avoidances:[],references:[{title:"Timestamp Dependence Vulnerability",link:"https://consensys.github.io/smart-contract-best-practices/development-recommendations/solidity-specific/timestamp-dependence/"}],updated:"2026-06-15",keywords:["时间戳依赖攻击","时间戳依赖","时间戳操纵","区块时间攻击","矿工操纵","timestamp manipulation"]},kn={R0176:wn},yn=e({R0177:()=>hn,default:()=>mn}),hn={title:"不可升级合约设计缺陷",definition:"智能合约部署后无法修改或升级，设计缺陷或漏洞将永久存在，造成长期风险。",description:"区块链智能合约的不可篡改特性是双刃剑。未设计升级机制的合约一旦部署，即使发现严重漏洞或业务逻辑错误也无法修复，只能弃用并重新部署。这会导致：已锁定资产无法取回、业务逻辑错误持续影响、无法适应需求变化。即使使用代理模式等升级方案，也可能引入新的中心化风险和升级权限滥用问题。",complexity:"高级",influence:"合约漏洞无法修复，资金永久锁定，业务无法迭代优化。",avoidances:["A0140","A0141","A0142"],references:[{title:"Smart Contract Upgradeability",link:"https://docs.openzeppelin.com/upgrades-plugins/1.x/proxies"}],updated:"2026-06-15",keywords:["不可升级合约设计缺陷","不可升级合约","合约设计缺陷","合约升级","代理模式","合约治理","immutable contract"]},mn={R0177:hn},gn=e({R0178:()=>In,default:()=>Rn}),In={title:"IoT侧信道攻击",definition:"通过分析物联网设备运行时的物理特征（功耗、电磁辐射、声音等）获取敏感信息或密钥。",description:"侧信道攻击利用设备在执行操作时产生的物理侧信道信息来推断内部数据。常见手段包括：功耗分析攻击（SPA/DPA）、电磁辐射分析、时序攻击、声学攻击、温度分析等。攻击者无需直接破解加密算法，通过物理信号即可提取密钥、还原敏感数据。物联网设备因资源受限和物理可接近性而尤其脆弱。",complexity:"高级",influence:"加密密钥被提取，设备固件被完整复制，用户隐私数据泄露。",avoidances:["A0143","A0144","A0145"],references:[{title:"Side-Channel Attacks on IoT",link:"https://www.usenix.org/conference/usenixsecurity19/presentation/van-geest"}],updated:"2026-06-15",keywords:["IoT侧信道攻击","侧信道攻击","功耗分析","电磁泄漏","时序攻击","物理攻击","side-channel attack"]},Rn={R0178:In},vn=e({R0179:()=>Sn,default:()=>Pn}),Sn={title:"工业物联网(IIoT)安全风险",definition:"工业物联网设备和系统面临的特殊安全威胁，可能导致生产中断、设备损坏或人身安全事故。",description:"工业物联网连接着生产设备、传感器、控制系统等关键基础设施。攻击者可通过入侵IIoT设备来：篡改生产参数造成产品质量问题、破坏设备运行引发安全事故、窃取工业机密、发起针对性勒索。IIoT设备通常生命周期长、难以更新、使用不安全的工业协议（如Modbus、SCADA），且与IT网络互联后暴露面扩大。",complexity:"高级",influence:"生产线瘫痪，设备损毁，人员伤亡，工业机密泄露，供应链中断。",avoidances:["A0146","A0147","A0148"],references:[{title:"ICS-CERT Advisories",link:"https://www.cisa.gov/topics/industrial-control-systems"}],updated:"2026-06-15",keywords:["工业物联网(IIoT)安全风险","工业物联网","IIoT安全","工控系统","SCADA攻击","生产安全","industrial IoT"]},Pn={R0179:Sn},xn=e({R0180:()=>Tn,default:()=>Cn}),Tn={title:"车联网(V2X)安全风险",definition:"车联网通信系统面临的安全威胁，可能导致交通事故、隐私泄露或车辆被远程控制。",description:"车联网(V2X)实现车与车(V2V)、车与基础设施(V2I)、车与行人(V2P)的通信。攻击者可通过：伪造虚假交通信息引发事故、劫持车辆通信系统、远程控制车辆关键功能（刹车、转向）、窃取车主位置和行驶数据、干扰自动驾驶决策等方式威胁安全。车辆CAN总线、OBD接口、车载娱乐系统等都是潜在攻击面。",complexity:"高级",influence:"交通事故致人伤亡，车辆被远程控制，用户行踪隐私泄露，自动驾驶系统失效。",avoidances:[],references:[{title:"Vehicle Cybersecurity Best Practices",link:"https://www.nhtsa.gov/technology-innovation/vehicle-cybersecurity"}],updated:"2026-06-15",keywords:["车联网(V2X)安全风险","车联网","V2X安全","智能汽车","远程劫持","CAN总线","自动驾驶安全","connected vehicle"]},Cn={R0180:Tn},bn=e({R0181:()=>Mn,default:()=>Fn}),Mn={title:"OTA更新劫持",definition:"攻击者劫持物联网设备的空中下载(OTA)更新过程，植入恶意固件或阻止安全更新。",description:"OTA更新是物联网设备远程升级固件的主要方式。攻击者可通过中间人攻击劫持更新通道、伪造更新服务器、利用更新协议漏洞等方式，向设备推送恶意固件或阻止安全补丁安装。如果更新包未加密签名验证或验证机制存在缺陷，设备将安装恶意固件并长期被控制。",complexity:"高级",influence:"设备被植入后门固件，安全漏洞无法修复，批量设备被持续控制。",avoidances:["A0149","A0150","A0151"],references:[{title:"Secure OTA Update Best Practices",link:"https://www.iotsecurityfoundation.org/best-practice-guidelines/"}],updated:"2026-06-15",keywords:["OTA更新劫持","OTA劫持","固件更新劫持","空中下载攻击","更新通道劫持","恶意固件推送","OTA hijacking"]},Fn={R0181:Mn},Dn=e({R0182:()=>Ln,default:()=>On}),Ln={title:"IoT数据篡改攻击",definition:"攻击者篡改物联网设备传输或存储的数据，导致错误决策或系统失效。",description:"物联网设备采集、传输和存储大量敏感数据，如果缺乏完整性保护，攻击者可通过中间人攻击、设备入侵等方式篡改数据。典型场景包括：篡改传感器读数影响自动化决策（如温度、压力、湿度）、修改设备日志掩盖攻击痕迹、伪造身份认证数据、篡改控制指令等。在工业、医疗、智慧城市等场景中可能造成严重后果。",complexity:"高级",influence:"基于错误数据做出危险决策，系统控制失效，攻击行为被隐藏，审计日志不可信。",avoidances:[],references:[{title:"IoT Data Integrity Protection",link:"https://www.nist.gov/publications/cybersecurity-framework-iot"}],updated:"2026-06-15",keywords:["IoT数据篡改攻击","数据篡改","传感器数据伪造","数据完整性","IoT数据攻击","控制指令篡改","data tampering"]},On={R0182:Ln},Nn=e({R0183:()=>Bn,default:()=>Wn}),Bn={title:"虚拟土地/资产欺诈",definition:"元宇宙中虚拟土地或数字资产交易中的欺诈行为，包括虚假销售、重复销售、价格操纵等。",description:"元宇宙虚拟土地和资产交易市场存在多种欺诈风险：项目方虚假宣传稀缺性后超量发售、同一地块重复销售给多人、操纵稀缺土地价格后抛售、伪造虚拟资产所有权证明、虚假承诺未来收益等。由于缺乏统一监管和确权机制，投资者维权困难，资金损失难以追回。",complexity:"中级",influence:"投资者资金损失，虚拟资产权属纠纷，元宇宙市场信任崩塌。",avoidances:["A0152","A0153","A0154"],references:[{title:"Metaverse Real Estate Fraud",link:"https://www.forbes.com/sites/digital-assets/metaverse-real-estate/"}],updated:"2026-06-15",keywords:["虚拟土地/资产欺诈","虚拟土地欺诈","元宇宙欺诈","虚拟地产","数字资产欺诈","虚拟资产","metaverse fraud"]},Wn={R0183:Bn},_n=e({R0184:()=>En,default:()=>Vn}),En={title:"元宇宙身份盗用",definition:"攻击者盗用或伪造用户在元宇宙中的虚拟身份，进行欺诈、骚扰或资产窃取。",description:"元宇宙中用户通过数字身份（头像、账号、NFT身份等）进行社交和交易。攻击者可通过盗取账号凭证、伪造相似头像身份、利用深度伪造技术冒充他人等方式，在元宇宙中实施欺诈、诈骗好友、窃取虚拟资产、破坏声誉、进行骚扰等恶意行为。去中心化身份系统的不完善使得身份验证和追责困难。",complexity:"高级",influence:"用户虚拟资产被盗，社交关系网络被破坏，声誉受损，遭受欺诈损失。",avoidances:[],references:[{title:"Metaverse Identity Security",link:"https://www.w3.org/TR/did-core/"}],updated:"2026-06-15",keywords:["元宇宙身份盗用","虚拟身份伪造","数字身份","头像冒充","身份欺诈","identity theft"]},Vn={R0184:En},Gn=e({R0185:()=>jn,default:()=>zn}),jn={title:"虚拟世界资产盗窃",definition:"元宇宙中用户虚拟资产（装备、道具、货币、NFT等）被非法窃取或转移。",description:"元宇宙中的虚拟资产具有真实经济价值，成为攻击者目标。盗窃手段包括：利用智能合约漏洞转移NFT资产、通过社会工程骗取钱包私钥、入侵游戏服务器窃取道具、利用交易系统漏洞复制资产、钓鱼网站诱导授权等。虚拟资产的数字化特性使其易被批量盗取和快速转移，且跨境追踪困难。",complexity:"高级",influence:"用户虚拟财产损失，元宇宙经济体系失衡，平台信誉受损。",avoidances:["A0155","A0156","A0157"],references:[{title:"Virtual Asset Security Best Practices",link:"https://www.fatf-gafi.org/publications/fatfrecommendations/documents/guidance-rba-virtual-assets.html"}],updated:"2026-06-15",keywords:["虚拟世界资产盗窃","虚拟资产盗窃","NFT盗窃","游戏资产盗窃","虚拟货币盗窃","数字财产","virtual asset theft"]},zn={R0185:jn},Un=e({R0186:()=>qn,default:()=>Hn}),qn={title:"日食攻击（Eclipse Attack）",definition:"攻击者通过控制目标节点的所有网络连接，将其与诚实网络隔离，操纵其接收的区块链信息。",description:"日食攻击针对P2P网络中的单个节点，攻击者通过女巫节点占据目标节点的所有连接槽位，使其与真实网络隔离。被隔离的节点只能从攻击者处接收信息，攻击者可向其提供虚假区块链视图、隐藏交易、双花攻击、或使其进行错误的共识投票。对于轻节点和SPV客户端尤其脆弱。",complexity:"高级",influence:"节点接收虚假区块链数据，交易被双花，共识投票被操纵，网络分区。",avoidances:["A0158","A0159","A0160"],references:[{title:"Eclipse Attacks on Bitcoin's Peer-to-Peer Network",link:"https://www.usenix.org/conference/usenixsecurity15/technical-sessions/presentation/heilman"}],updated:"2026-06-15",keywords:["日食攻击（Eclipse Attack）","日食攻击","节点隔离","网络分区","P2P攻击","连接垄断","eclipse attack"]},Hn={R0186:qn},Qn=e({R0187:()=>Kn,default:()=>Xn}),Kn={title:"长程攻击/无成本模拟",definition:"PoS区块链中，攻击者利用历史私钥从创世区块开始构造替代链，试图覆盖主链历史。",description:"长程攻击(Long-range Attack)是PoS共识机制特有的威胁。攻击者获取早期权益持有者的私钥后，可以从区块链历史中的任意点分叉并构建替代链。由于PoS验证不需要实际算力消耗（无成本模拟，Nothing-at-Stake），攻击者可以低成本构造更长的链。新加入网络的节点可能将伪造链误认为是主链。",complexity:"高级",influence:"区块链历史被改写，交易被逆转，新节点接受虚假链，共识机制信任崩塌。",avoidances:["A0161","A0162","A0163"],references:[{title:"Long-Range Attacks on Proof-of-Stake",link:"https://blog.ethereum.org/2014/05/15/long-range-attacks-the-serious-problem-with-adaptive-proof-of-work"}],updated:"2026-06-15",keywords:["长程攻击/无成本模拟","长程攻击","无成本模拟","PoS攻击","历史改写","私钥窃取","long-range attack","nothing-at-stake"]},Xn={R0187:Kn},Yn=e({R0188:()=>Jn,default:()=>Zn}),Jn={title:"自私挖矿（Selfish Mining）",definition:"矿工故意隐藏挖出的区块，在特定时机公布以获得超额收益，破坏区块链公平性。",description:"自私挖矿是一种矿工策略攻击。矿工挖出新区块后不立即广播，而是继续在私有链上挖矿。当公共链追上时，选择性地公布私有链使其成为主链，作废其他矿工的工作。这种策略可使拥有超过33%算力的矿池获得超出其算力占比的收益，同时降低网络整体安全性和浪费算力资源。",complexity:"高级",influence:"诚实矿工收益降低，算力资源浪费，区块链安全性下降，中心化趋势加剧。",avoidances:["A0164","A0165","A0166"],references:[{title:"Majority is not Enough: Bitcoin Mining is Vulnerable",link:"https://www.cs.cornell.edu/~ie53/publications/btcProcFC.pdf"}],updated:"2026-06-15",keywords:["自私挖矿（Selfish Mining）","自私挖矿","矿工攻击","区块隐藏","策略攻击","算力操纵","selfish mining"]},Zn={R0188:Jn},$n=e({R0189:()=>ea,default:()=>ia}),ea={title:"传感器欺骗攻击",definition:"攻击者通过物理或电子手段欺骗物联网传感器，使其采集到虚假数据，导致系统做出错误决策。",description:"传感器是物联网系统的数据来源，其准确性直接影响系统决策。攻击者可通过多种方式欺骗传感器：物理干扰（如用强光欺骗光传感器、用热源欺骗温度传感器）、电磁干扰、信号注入、传感器饱和攻击等。在自动驾驶、工业控制、智能家居、安防监控等场景中，虚假传感器数据可能导致严重后果。",complexity:"高级",influence:"系统基于错误数据做出危险决策，安全机制被绕过，事故风险增加，监控失效。",avoidances:[],references:[{title:"Sensor Spoofing Attacks on IoT Systems",link:"https://www.usenix.org/conference/usenixsecurity17/technical-sessions/presentation/trippel"}],updated:"2026-06-15",keywords:["传感器欺骗攻击","传感器欺骗","传感器攻击","虚假数据","物理欺骗","信号注入","sensor spoofing"]},ia={R0189:ea},ta=e({R0190:()=>na,default:()=>aa}),na={title:"医疗物联网(IoMT)安全风险",definition:"医疗物联网设备面临的特殊安全威胁，可能直接危及患者生命安全和隐私。",description:"医疗物联网(IoMT)连接着心脏起搏器、胰岛素泵、输液泵、监护仪等关键医疗设备。攻击者可通过无线劫持、固件篡改、协议漏洞等方式控制设备，造成：错误用药剂量导致患者伤亡、篡改生命体征数据误导诊断、关闭救生设备、窃取患者敏感健康隐私等。医疗设备通常更新困难、认证周期长、使用寿命长，安全防护薄弱。",complexity:"高级",influence:"患者生命安全受威胁，健康隐私大规模泄露，医疗事故，医院运营瘫痪，法律责任。",avoidances:[],references:[{title:"FDA Medical Device Cybersecurity Guidance",link:"https://www.fda.gov/medical-devices/digital-health-center-excellence/cybersecurity"}],updated:"2026-06-15",keywords:["医疗物联网(IoMT)安全风险","医疗物联网","IoMT安全","医疗设备安全","植入式设备","健康隐私","medical device security"]},aa={R0190:na},sa=e({R0191:()=>oa,default:()=>ca}),oa={title:"AR/VR设备安全风险",definition:"增强现实(AR)和虚拟现实(VR)设备面临的特殊安全威胁，可能导致隐私泄露、物理伤害或设备劫持。",description:"AR/VR设备集成了大量传感器（摄像头、麦克风、眼动追踪、手势识别等）和沉浸式交互，面临独特风险：设备被劫持后持续监控用户视觉和听觉、窃取眼动数据推断敏感信息（如密码、健康状况）、篡改现实叠加内容误导用户行为、VR晕动症攻击影响身体健康、未成年人不当内容接触等。设备固件和应用生态安全防护不足。",complexity:"高级",influence:"用户隐私全方位泄露，生物特征数据被窃，物理空间安全威胁，心理健康影响。",avoidances:[],references:[{title:"VR/AR Security and Privacy Challenges",link:"https://www.usenix.org/conference/usenixsecurity18/presentation/lebeck"}],updated:"2026-06-15",keywords:["AR/VR设备安全风险","AR/VR安全","增强现实","虚拟现实","眼动追踪","沉浸式攻击","XR设备","VR privacy"]},ca={R0191:oa},ra=e({R0192:()=>la,default:()=>da}),la={title:"虚拟世界骚扰与暴力",definition:"元宇宙中用户遭受的虚拟骚扰、暴力行为和不当内容，可能造成心理创伤和现实危害。",description:"元宇宙的沉浸式特性使虚拟骚扰和暴力的心理影响接近真实体验。风险包括：虚拟性骚扰和侵犯个人空间、语言暴力和网络霸凌、虚拟暴力行为的心理创伤、未成年人接触不当内容、深度伪造技术制造虚假不雅内容、虚拟跟踪和骚扰等。由于匿名性和跨境特性，追责和监管困难，受害者保护机制不完善。",complexity:"中级",influence:"用户心理创伤和PTSD，未成年人身心健康受损，平台声誉和法律责任，用户流失。",avoidances:[],references:[{title:"Virtual Harassment and Safety in Metaverse",link:"https://www.sciencedirect.com/science/article/pii/S0747563222003818"}],updated:"2026-06-15",keywords:["虚拟世界骚扰与暴力","虚拟骚扰","虚拟暴力","网络霸凌","元宇宙安全","心理创伤","未成年人保护","virtual harassment"]},da={R0192:la};export{ui as $,Ct as A,C as At,Zi as B,Xt as C,X as Ct,Wt as D,W as Dt,Vt as E,V as Et,ut as F,u as Ft,Wi as G,Hi as H,dt as I,d as It,Ci as J,Oi as K,ct as L,c as Lt,Rt as M,R as Mt,mt as N,m as Nt,Ot as O,O as Ot,kt as P,k as Pt,ki as Q,at as R,a as Rt,Zt as S,Z as St,zt as T,z as Tt,zi as U,Xi as V,Vi as W,Ri as X,Pi as Y,mi as Z,fn as _,ue as _t,Yn as a,Xe as at,sn as b,ae as bt,Gn as c,Ve as ct,Dn as d,Fe as dt,di as et,bn as f,Ce as ft,yn as g,ke as gt,gn as h,me as ht,$n as i,Ze as it,Pt as j,P as jt,Ft as k,F as kt,_n as l,We as lt,vn as m,Re as mt,sa as n,ai as nt,Qn as o,He as ot,xn as p,Pe as pt,Fi as q,ta as r,ii as rt,Un as s,ze as st,ra as t,ci as tt,Nn as u,Oe as ut,An as v,de as vt,Ht as w,H as wt,tn as x,ie as xt,rn as y,ce as yt,it as z,i as zt};